function formatSymbols(symbols: string[]): string {
  if (symbols.length === 0) return "";
  const shown = symbols.slice(0, 5);
  const rest = symbols.length - shown.length;
  const suffix = rest > 0 ? `, +${rest}` : "";
  return chalk.gray(` {${shown.join(", ")}${suffix}}`);
}

