  mmr?: boolean;
  /** MMR diversity weight: 0=max diversity, 1=pure relevance (default: 0.5) */
  lambda?: number;
  /** Merge adjacent or overlapping chunks from the same file */
  merge?: boolean;
  /** Max line gap between chunks to still merge them (default: 3) */
  mergeGap?: number;
