      console.log(chalk.gray("  imports:"));
      for (const imp of shown) {
        const syms =
          imp.symbols.length > 0
            ? chalk.gray(
                ` {${imp.symbols.slice(0, 4).join(", ")}${imp.symbols.length > 4 ? ", …" : ""}}`,
              )
