  const cache = cacheStorage.load();

  const row = (label: string, value: string) =>
    console.log(`  ${chalk.gray(label.padEnd(16))} ${value}`);

  console.log(chalk.bold("vemora status"));
  console.log();
  row("Project:", config.projectName);
  row("Project ID:", config.projectId);
  row("Provider:", `${config.embedding.provider} / ${config.embedding.model}`);

  if (meta) {
    console.log();
    console.log(chalk.bold("Index (versioned in git):"));
    row("Last indexed:", meta.lastIndexed ?? chalk.gray("never"));
    row("Files:", String(meta.indexedFiles));
    row("Chunks:", String(meta.totalChunks));
    row("Symbols:", String(meta.totalSymbols));
    row("Dep edges:", String(meta.totalDepEdges ?? 0));
    row("Call edges:", String(meta.totalCallEdges ?? 0));
  }

  // Summaries
  const summaryStorage = new SummaryStorage(rootDir);
  if (summaryStorage.hasFileSummaries()) {
    const fileSummaries = summaryStorage.loadFileSummaries();
    const summaryCount = Object.keys(fileSummaries).length;
    const hasOverview = summaryStorage.hasProjectSummary();
    console.log();
    console.log(chalk.bold("Summaries (versioned in git):"));
    row("File summaries:", String(summaryCount));
    row(
      "Project overview:",
      hasOverview
        ? chalk.green("yes")
        : chalk.gray("no  (run vemora summarize)"),
    );
  }

  // Knowledge store
  const knowledgeStorage = new KnowledgeStorage(rootDir);
  if (knowledgeStorage.hasKnowledge()) {
    const entries = knowledgeStorage.load();
    console.log();
    console.log(chalk.bold("Knowledge store (versioned in git):"));
    row("Entries:", String(entries.length));

    // Staleness detection: warn if relatedFiles were modified after entry was created
    const fileIndex = repo.loadFiles();
    const stale = entries.filter((e) => {
      if (!e.relatedFiles?.length) return false;
      return e.relatedFiles.some((f) => {
        const fileEntry = fileIndex[f];
        if (!fileEntry) return false;
        // If we have a hash snapshot, use it — immune to touch/timestamp skew
        if (e.relatedFileHashes?.[f]) {
          return fileEntry.hash !== e.relatedFileHashes[f];
        }
        // Fallback for older entries without hash snapshots
        if (fileEntry.hash && e.createdAt) {
          return new Date(fileEntry.lastModified) > new Date(e.createdAt);
        }
        return false;
      });
    });

    if (stale.length > 0) {
      console.log();
      for (const e of stale) {
        console.log(
          `  ${chalk.yellow("⚠")}  Knowledge entry ${chalk.gray(`[${e.id.slice(0, 8)}]`)} ${chalk.bold(`"${e.title}"`)} — related files changed after entry was created`,
        );
        console.log(
          chalk.gray(
            `     Created: ${e.createdAt.slice(0, 10)} · Run \`vemora knowledge list\` to review`,

      console.log();
      for (const e of stale) {
        console.log(
          `  ${chalk.yellow("⚠")}  Knowledge entry ${chalk.gray(`[${e.id.slice(0, 8)}]`)} ${chalk.bold(`"${e.title}"`)} — related files changed after entry was created`,
        );
        console.log(
          chalk.gray(
            `     Created: ${e.createdAt.slice(0, 10)} · Run \`vemora knowledge list\` to review`,
          ),
        );
      }
    }
  }

  // TODO / FIXME annotations
  const todos = repo.loadTodos();
  if (todos.length > 0) {
    const byType = todos.reduce<Record<string, number>>((acc, t) => {
      acc[t.type] = (acc[t.type] ?? 0) + 1;
      return acc;
    }, {});
    console.log();
    console.log(chalk.bold("Code annotations (versioned in git):"));
    row("Total:", String(todos.length));
    for (const [type, count] of Object.entries(byType).sort()) {
      row(`  ${type}:`, String(count));
    }
  }

  // Circular dependency detection
  const deps = repo.loadDeps();
  const cycles = detectCycles(deps);
  if (cycles.length > 0) {
    console.log();
    console.log(chalk.bold("Circular dependencies:"));
    for (const cycle of cycles) {
      const display = cycle
        .map((f) => chalk.cyan(path.basename(f)))
        .join(chalk.gray(" → "));
      console.log(`  ${chalk.yellow("⚠")}  ${display}`);
    }
  }

  console.log();
  console.log(chalk.bold("Embedding cache (local only):"));
  const cachedCount = cache?.chunkIds
    ? cache.chunkIds.length
    : Object.keys(cache?.embeddings ?? {}).length;
  if (!cache || cachedCount === 0) {
    console.log(
      `  ${chalk.gray("No cache found.")} Run ${chalk.cyan("vemora index")} to generate embeddings.`,
    );
  } else {
    row("Cached vectors:", String(cachedCount));
    row("Model:", cache.embeddingModel);
    row("Updated:", cache.lastUpdated);
    row("Location:", cacheStorage.getCacheDir());
  }
}

import chalk from "chalk";
import fs from "fs";
import OpenAI from "openai";
import ora from "ora";
import path from "path";
import { loadConfig } from "../core/config";
import type { FileSummaryIndex, ProjectSummary } from "../core/types";
import { RepositoryStorage } from "../storage/repository";
import { SummaryStorage } from "../storage/summaries";

export interface SummarizeOptions {
  /** Re-generate all summaries, ignoring content hashes */
  force?: boolean;
  /** Override the model from config (e.g. gpt-4o, gpt-4o-mini) */
  model?: string;
  /** Only generate file-level summaries, skip project overview */
  filesOnly?: boolean;
  /** Only (re)generate the project overview from existing file summaries */
  projectOnly?: boolean;
}

function fileSummaryPrompt(
  file: string,
  symbols: string[],
  content: string,
): string {
  const symbolList = symbols.length > 0 ? symbols.join(", ") : "none";
  return (
    `You are summarizing a source code file for a code memory system used by AI assistants.\n` +
    `Write 2-3 concise sentences describing:\n` +
    `1. What this file does and its main responsibility\n` +
    `2. Key symbols it exports (functions, classes, interfaces)\n` +
    `3. Its role in the broader codebase (if apparent from the path and content)\n\n` +
    `Be specific and technical. No preamble, no bullet points. Plain prose only.\n\n` +
    `File: ${file}\n` +
    `Key symbols: ${symbolList}\n\n` +
    `Content:\n\`\`\`\n${content}\n\`\`\``
  );
}

function projectOverviewPrompt(projectName: string, summaries: string): string {
  return (
    `You are creating a high-level overview of a software project called "${projectName}" ` +
    `for an AI assistant's persistent memory system.\n\n` +
    `This overview will always be included in the AI's context when working on this project, ` +
    `so it must be information-dense and accurate.\n\n` +
    `Write 400-500 words covering:\n` +
    `1. What this project does (its purpose and main features)\n` +
    `2. Main architectural layers and components\n` +
    `3. Key data flows and how components interact\n` +
    `4. Entry points for common development tasks\n\n` +
    `Be technical and precise. No preamble.\n\n` +
    `File summaries:\n${summaries}`
  );
}

export async function runSummarize(
  rootDir: string,
  options: SummarizeOptions = {},
): Promise<void> {
  const config = loadConfig(rootDir);
  const repo = new RepositoryStorage(rootDir);
  const summaryStorage = new SummaryStorage(rootDir);

  // ── Resolve API settings ────────────────────────────────────────────────────
  const model = options.model ?? config.summarization?.model ?? "gpt-4o-mini";
  const apiKey = config.summarization?.apiKey ?? process.env.OPENAI_API_KEY;
  const baseUrl = config.summarization?.baseUrl;

  if (!apiKey) {
    throw new Error(
      "No API key found. Set OPENAI_API_KEY env var or add summarization.apiKey to .vemora/config.json",
    );
  }

  const openai = new OpenAI({
    apiKey,
    ...(baseUrl ? { baseURL: baseUrl } : {}),
  });

  // ── File summaries ──────────────────────────────────────────────────────────

  let anyFileSummaryChanged = false;

  if (!options.projectOnly) {
    const files = repo.loadFiles();
    const prevSummaries = summaryStorage.loadFileSummaries();

    const allEntries = Object.entries(files);
    const toSummarize = options.force
      ? allEntries
      : allEntries.filter(([relPath, entry]) => {
          const prev = prevSummaries[relPath];
          return !prev || prev.contentHash !== entry.hash;
        });

    const skipped = allEntries.length - toSummarize.length;

    console.log(chalk.bold(`Summarizing ${chalk.cyan(config.projectName)}`));
    console.log(chalk.gray(`  model: ${model}`));
    console.log();
    console.log(
      chalk.bold("File summaries") +
        chalk.gray(
          `  ${toSummarize.length} to generate` +
            (skipped > 0 ? `, ${skipped} unchanged (skipped)` : ""),
        ),
    );
    console.log();

    if (toSummarize.length === 0) {
      console.log(chalk.green("✓ All file summaries are up to date."));
    } else {
      const updated: FileSummaryIndex = { ...prevSummaries };
      let failed = 0;

      for (let i = 0; i < toSummarize.length; i++) {
        const [relPath, entry] = toSummarize[i];
        const label = `[${i + 1}/${toSummarize.length}] ${relPath}`;
        const spinner = ora(chalk.gray(label)).start();

        try {
          // Read file content, truncate to ~4000 chars to stay within prompt limits
          const absolutePath = path.join(rootDir, relPath);
          let content = "";
          if (fs.existsSync(absolutePath)) {
            const raw = fs.readFileSync(absolutePath, "utf-8");
            content =
              raw.length > 4000
                ? raw.slice(0, 4000) + "\n... (truncated)"
                : raw;
          }

          const fileSymbols = entry.symbols ?? [];

          const response = await openai.chat.completions.create({

            raw.length > 4000
              ? raw.slice(0, 4000) + "\n... (truncated)"
              : raw;
        }

        const fileSymbols = entry.symbols ?? [];

        const response = await openai.chat.completions.create({
          model,
          messages: [
            {
              role: "user",
              content: fileSummaryPrompt(relPath, fileSymbols, content),
            },
          ],
          max_tokens: 250,
          temperature: 0,
        });

        const summary = response.choices[0]?.message?.content?.trim() ?? "";

        updated[relPath] = {
          summary,
          contentHash: entry.hash,
          generatedAt: new Date().toISOString(),
        };

        spinner.succeed(chalk.gray(relPath));
        anyFileSummaryChanged = true;
      } catch (err) {
        spinner.fail(chalk.red(`${relPath}: ${(err as Error).message}`));
        failed++;
      }
    }

    summaryStorage.saveFileSummaries(updated);

    console.log();
    console.log(
      chalk.green(`✓ ${toSummarize.length - failed} file summaries saved`) +
        (failed > 0 ? chalk.red(` (${failed} failed)`) : "") +
        chalk.gray("  →  .vemora/summaries/file-summaries.json"),
    );
  }

  if (options.filesOnly) return;
  console.log();
}

// ── Project overview ────────────────────────────────────────────────────────

if (
  !anyFileSummaryChanged &&
  !options.force &&
  !options.projectOnly &&
  summaryStorage.hasProjectSummary()
) {
  console.log(chalk.green("✓ Project overview is up to date."));
  return;
}

const currentSummaries = summaryStorage.loadFileSummaries();
const summaryEntries = Object.entries(currentSummaries);

if (summaryEntries.length === 0) {
  console.log(
    chalk.yellow(
      "No file summaries found. Run `vemora summarize` (without --project-only) first.",
    ),
  );
  return;
}

const overviewSpinner = ora("Generating project overview...").start();

// Build the file summaries block, sorted and truncated to fit context
const MAX_SUMMARY_CHARS = 12000;
let summaryBlock = summaryEntries
  .sort(([a], [b]) => a.localeCompare(b))
  .map(([file, { summary }]) => `${file}:\n  ${summary}`)

  const overviewSpinner = ora("Generating project overview...").start();

  // Build the file summaries block, sorted and truncated to fit context
  const MAX_SUMMARY_CHARS = 12000;
  let summaryBlock = summaryEntries
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([file, { summary }]) => `${file}:\n  ${summary}`)
    .join("\n\n");

  if (summaryBlock.length > MAX_SUMMARY_CHARS) {
    summaryBlock =
      summaryBlock.slice(0, MAX_SUMMARY_CHARS) + "\n... (truncated)";
  }

  try {
    const response = await openai.chat.completions.create({
      model,
      messages: [
        {
          role: "user",
          content: projectOverviewPrompt(config.projectName, summaryBlock),
        },
      ],
      max_tokens: 750,
      temperature: 0.1,
    });

    const overview = response.choices[0]?.message?.content?.trim() ?? "";

    const projectSummary: ProjectSummary = {
      overview,
      generatedAt: new Date().toISOString(),
    };

    summaryStorage.saveProjectSummary(projectSummary);
    overviewSpinner.succeed(
      "Project overview saved" +
        chalk.gray("  →  .vemora/summaries/project-summary.json"),
    );

    // Print a short preview
    console.log();
    const previewLines = overview.split("\n").slice(0, 5);
    for (const line of previewLines) {
      console.log("  " + chalk.gray(line));
    }
    if (overview.split("\n").length > 5) {
      console.log(chalk.gray("  … (use `vemora overview` to read in full)"));
    }
  } catch (err) {
    overviewSpinner.fail(`Project overview failed: ${(err as Error).message}`);
  }
}

import crypto from "crypto";
import fs from "fs";
import os from "os";
import path from "path";
import type { AiMemoryConfig } from "./types";

// ─── Path Constants ────────────────────────────────────────────────────────────

export function getMemoryDir(rootDir: string): string {
  return path.join(rootDir, AI_MEMORY_DIR);
}

export function getIndexDir(rootDir: string): string {
  return path.join(rootDir, AI_MEMORY_DIR, INDEX_DIR);
}

export function getSummariesDir(rootDir: string): string {
  return path.join(rootDir, AI_MEMORY_DIR, SUMMARIES_DIR);
}

export function getLocalCacheDir(projectId: string): string {
  return path.join(os.homedir(), ".vemora-cache", projectId);
}

export function generateProjectId(rootDir: string): string {
  return crypto.createHash("sha256").update(rootDir).digest("hex").slice(0, 16);
}

export function loadConfig(rootDir: string): AiMemoryConfig {
  const configPath = path.join(rootDir, AI_MEMORY_DIR, CONFIG_FILE);
  if (!fs.existsSync(configPath)) {
    throw new Error(
      `No ${AI_MEMORY_DIR}/config.json found in ${rootDir}.\nRun 'vemora init' first.`,
    );
  }
  const raw = fs.readFileSync(configPath, "utf-8");
  const config = JSON.parse(raw) as AiMemoryConfig;
  // rootDir is injected at load time (not stored in config) so it always reflects
  // the actual filesystem location, even if the project was moved.
  config.rootDir = rootDir;
  return config;
}

export function saveConfig(config: AiMemoryConfig): void {
  const configPath = path.join(config.rootDir, AI_MEMORY_DIR, CONFIG_FILE);
  // Don't persist rootDir — it's injected at load time
  const { rootDir: _omit, ...toSave } = config;
  fs.writeFileSync(configPath, JSON.stringify(toSave, null, 2), "utf-8");
}

export interface DisplayConfig {
  /**
   * Default output format for query/context/ask commands.
   * Set to "terse" for small/local models with limited context windows.
   * Can always be overridden per-command with --format.
   */
  format?: "terse" | "markdown";
}

export interface AiMemoryConfig {
  /** Deterministic project ID derived from root directory path */
  projectId: string;
  projectName: string;
  /** Schema version of this config file */
  version: string;
  /** Absolute path to project root (injected at load time, not persisted) */
  rootDir: string;
  /** fast-glob patterns of files to include */
  include: string[];
  /** fast-glob patterns to exclude (node_modules, build outputs, etc.) */
  exclude: string[];
  /** Max lines per chunk before splitting */
  maxChunkLines: number;
  /** Max characters per chunk before splitting */
  maxChunkChars: number;
  embedding: EmbeddingConfig;
  /** Configuration for LLM-based summarization (vemora summarize) */
  summarization?: SummarizationConfig;
  /** Output display preferences */
  display?: DisplayConfig;
  /** Human-readable description of where the local cache lives */
  cacheDir: string;
}

export interface SummarizationConfig {
  provider: "openai" | "anthropic" | "ollama";
  /** Chat completion model (default: gpt-4o-mini) */
  model: string;
  /** API key. Defaults to OPENAI_API_KEY / ANTHROPIC_API_KEY env vars. */
  apiKey?: string;
  /** Base URL for OpenAI-compatible or Ollama APIs */
  baseUrl?: string;
}

export interface EmbeddingConfig {
  provider: "openai" | "ollama" | "none";
  model: string;
  /** Vector dimensions — must match the model output */
  dimensions: number;
  /** API key for OpenAI. Defaults to OPENAI_API_KEY env var. */
  apiKey?: string;
  /** Base URL for Ollama. Defaults to http://localhost:11434 */
  baseUrl?: string;
}

export interface FileIndex {
  [relativePath: string]: FileEntry;
}

export interface FileEntry {
  /** SHA-256 hash of file content for change detection */
  hash: string;
  size: number;
  lastModified: string;
  /** IDs of all chunks extracted from this file */
  chunks: string[];
  /** Names of all symbols extracted from this file */
  symbols: string[];
}

export interface Chunk {
  /** Content-hash based ID. Stable across re-indexing if code doesn't change. */
  id: string;
  /** Relative file path */
  file: string;
  /** 1-based start line (inclusive) */
  start: number;
  /** 1-based end line (inclusive) */
  end: number;
  /** Symbol this chunk belongs to, if any */
  symbol?: string;
  /** The raw source text */
  content: string;
}

export interface SymbolIndex {
  [name: string]: SymbolEntry;
}

export interface SymbolEntry {
  type:
    | "function"
    | "class"
    | "method"
    | "interface"
    | "type"
    | "constant"
    | "variable";
  /** Relative file path */
  file: string;
  startLine: number;
  endLine: number;
  exported: boolean;
  /** For methods: the parent class name */
  parent?: string;
}

export interface DependencyGraph {
  [relativePath: string]: FileDependencies;
}

export interface FileDependencies {
  /** Project files this file imports from */
  imports: ImportEntry[];
}

export interface ImportEntry {
  /** Relative path of the imported file (within the project) */
  file: string;
  /** Named symbols imported. Empty = default / namespace / side-effect import. */
  symbols: string[];
}

export interface CallGraphEntry {
  /** The function/method name that is being called */
  name: string;
  /** The file containing the definition, if known */
  file?: string;
  /** Location in the file */
  line?: number;
}

export interface CallGraph {
  /** Map from function/method ID (file:symbol) to call info */
  [callerId: string]: {
    calls: CallGraphEntry[];
    calledBy: string[]; // List of caller IDs
  };
}

export interface Metadata {
  projectId: string;
  projectName: string;
  lastIndexed: string | null;
  indexedFiles: number;
  totalChunks: number;
  totalSymbols: number;
  totalDepEdges: number;
  totalCallEdges?: number; // Total number of calls tracked
  /** Files with AI-generated summaries (from vemora summarize) */
  totalSummaries?: number;
  embeddingProvider?: string;
  embeddingModel?: string;
}

export interface FileSummaryIndex {
  [relativePath: string]: FileSummary;
}

export interface FileSummary {
  /** 2-3 sentence description of the file's purpose and key exports */
  summary: string;
  /** SHA-256 hash of the file content at generation time (for incremental updates) */
  contentHash: string;
  /** ISO timestamp */
  generatedAt: string;
}

export interface ProjectSummary {
  /** High-level overview of the project's purpose, architecture, and components */
  overview: string;
  generatedAt: string;
}

export interface EmbeddingCache {
  projectId: string;
  embeddingModel: string;
  dimensions: number;
  lastUpdated: string;
  /** Map from chunk ID to its embedding vector (legacy JSON format) */
  embeddings?: Record<string, number[]>;
  /** Optimized: contiguous buffer of all vectors (runtime only) */
  vectors?: Float32Array; // Optimized binary format (dims * count)
  /** Optimized: ordered list of chunk IDs matching the vectors buffer */
  chunkIds?: string[]; // Maps index in vectors buffer to chunk ID
  hnswIndex?: unknown; // Serialized HNSW index for fast search
}

export interface KnowledgeEntry {
  /** UUID v4 */
  id: string;
  category: "decision" | "pattern" | "gotcha" | "glossary";
  /** Short title shown in context headers */
  title: string;
  /** Free-form text, searchable via keyword overlap */
  body: string;
  /** Project-relative file paths this entry is about */
  relatedFiles?: string[];
  /** SHA-256 hashes of relatedFiles at creation time, keyed by path */
  relatedFileHashes?: Record<string, string>;
  /** Symbol names this entry is about */
  relatedSymbols?: string[];
  /** ISO timestamp */
  createdAt: string;
  /** "human" or "llm:<model-id>" */
  createdBy: string;
  confidence: "high" | "medium" | "low";
  /** ID of the entry this supersedes (for updates) */
  supersedes?: string;
}

export interface TodoAnnotation {
  file: string;
  /** 1-based line number */
  line: number;
  type: "TODO" | "FIXME" | "HACK" | "XXX";
  text: string;
}

export interface SearchResult {
  chunk: Chunk;
  /** Cosine similarity score in [0, 1] (or keyword score for non-vector search) */
  score: number;
  /** Resolved symbol info if the chunk has a symbol */
  symbol?: SymbolEntry;
}

import type { EmbeddingConfig } from "../core/types";
import { NoopEmbeddingProvider } from "./noop";
import { OllamaEmbeddingProvider } from "./ollama";
import { OpenAIEmbeddingProvider } from "./openai";
import type { EmbeddingProvider } from "./provider";

/**
 * Factory that instantiates the correct EmbeddingProvider from config.
 * Adding a new provider only requires implementing EmbeddingProvider and
 * adding a case here — no other code needs to change.
 */

export function createEmbeddingProvider(
  config: EmbeddingConfig,
): EmbeddingProvider {
  switch (config.provider) {
    case "openai":
      return new OpenAIEmbeddingProvider(
        config.apiKey,
        config.model,
        config.dimensions,
      );

    case "ollama":
      return new OllamaEmbeddingProvider(
        config.model,
        config.baseUrl,
        config.dimensions,
      );

    case "none":
      return new NoopEmbeddingProvider();

    default: {
      const p = (config as EmbeddingConfig).provider;
      throw new Error(
        `Unknown embedding provider: "${p}". Valid options: openai, ollama, none`,
      );
    }
  }
}

export class NoopEmbeddingProvider implements EmbeddingProvider {
  readonly name = "none";
  readonly model = "none";
  readonly dimensions = 0;

  async embed(texts: string[]): Promise<number[][]> {
    return texts.map(() => []);
  }
}

export class NoopEmbeddingProvider implements EmbeddingProvider {
  readonly name = "none";
  readonly model = "none";
  readonly dimensions = 0;

  // ...

  async embed(texts: string[]): Promise<number[][]> {
    return texts.map(() => []);
  }

interface OllamaEmbedResponse {
  embedding: number[];
}

export class OllamaEmbeddingProvider implements EmbeddingProvider {
  readonly name = "ollama";
  readonly model: string;
  readonly dimensions: number;

  private baseUrl: string;

  constructor(
    model = "nomic-embed-text",
    baseUrl = "http://localhost:11434",
    dimensions = 768,
  ) {
    this.model = model;
    this.dimensions = dimensions;
    this.baseUrl = baseUrl.replace(/\/$/, "");
  }

  async embed(texts: string[]): Promise<number[][]> {
    if (texts.length === 0) return [];

    const results: number[][] = [];

    // Ollama's /api/embeddings endpoint processes one text at a time
    for (const text of texts) {
      const response = await fetch(`${this.baseUrl}/api/embeddings`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ model: this.model, prompt: text }),
      });

      if (!response.ok) {
        throw new Error(
          `Ollama embedding request failed: ${response.status} ${response.statusText}`,
        );
      }

      const data = (await response.json()) as OllamaEmbedResponse;
      results.push(data.embedding);
    }

    return results;
  }
}

export class OllamaEmbeddingProvider implements EmbeddingProvider {
  readonly name = "ollama";
  readonly model: string;
  readonly dimensions: number;

  private baseUrl: string;

  constructor(
    model = "nomic-embed-text",
    baseUrl = "http://localhost:11434",
    dimensions = 768,
  ) {
    this.model = model;
    this.dimensions = dimensions;
    this.baseUrl = baseUrl.replace(/\/$/, "");
  }

  // ...

  async embed(texts: string[]): Promise<number[][]> {
    if (texts.length === 0) return [];

    const results: number[][] = [];

    // Ollama's /api/embeddings endpoint processes one text at a time
    for (const text of texts) {
      const response = await fetch(`${this.baseUrl}/api/embeddings`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ model: this.model, prompt: text }),
      });

      if (!response.ok) {
        throw new Error(
          `Ollama embedding request failed: ${response.status} ${response.statusText}`,
        );
      }

      const data = (await response.json()) as OllamaEmbedResponse;
      results.push(data.embedding);
    }

    return results;
  }

import type { EmbeddingProvider } from "./provider";

/** Maximum inputs per API call (OpenAI allows up to 2048) */
const BATCH_SIZE = 2048;

export class OpenAIEmbeddingProvider implements EmbeddingProvider {
  readonly name = "openai";
  readonly model: string;
  readonly dimensions: number;

  // biome-ignore lint/suspicious/noExplicitAny: openai is an optional peer dependency
  private client: any;

  constructor(
    apiKey?: string,
    model = "text-embedding-3-small",
    dimensions = 1536,
  ) {
    this.model = model;
    this.dimensions = dimensions;
    let OpenAI: any;
    try {
      // biome-ignore lint/suspicious/noExplicitAny: optional peer dependency
      OpenAI = require("openai").default ?? require("openai");
    } catch {
      throw new Error(
        'Package "openai" is not installed. Run: npm install openai',
      );
    }
    this.client = new OpenAI({
      apiKey: apiKey ?? process.env.OPENAI_API_KEY,
    });
  }

  async embed(texts: string[]): Promise<number[][]> {
    if (texts.length === 0) return [];

    const results: number[][] = [];
    const batches: string[][] = [];
    for (let i = 0; i < texts.length; i += BATCH_SIZE) {
      batches.push(texts.slice(i, i + BATCH_SIZE));
    }

    const MAX_PARALLEL = 4;
    for (let i = 0; i < batches.length; i += MAX_PARALLEL) {
      const parallelBatches = batches.slice(i, i + MAX_PARALLEL);
      try {
        const responses = await Promise.all(
          parallelBatches.map(async (batch, idx) => {
            try {
              return await this.client.embeddings.create({
                model: this.model,
                input: batch,
                ...(this.model.startsWith("text-embedding-3") && {
                  dimensions: this.dimensions,
                }),
              });
            } catch (err) {
              console.error(`OpenAI embedding batch ${i + idx} failed:`, err);
              return { data: [] };
            }
          })
        );
        for (const response of responses) {
          const sorted = response.data.sort((a: any, b: any) => a.index - b.index);
          results.push(...sorted.map((e: any) => e.embedding));
        }
      } catch (err) {
        console.error(`OpenAI embedding batch group ${i / MAX_PARALLEL} failed:`, err);
      }
    }
    return results;
  }
}

