import type {
  CallGraph,
  CallGraphEntry,
  DependencyGraph,
  SymbolIndex,
} from "../core/types";

// Tree-sitter is optional, just like in parser.ts
// biome-ignore lint/suspicious/noExplicitAny: tree-sitter native bindings have no TS types
let Parser: any = null;
// biome-ignore lint/suspicious/noExplicitAny: tree-sitter native bindings have no TS types
let tsLanguage: any = null;

try {
  Parser = require("tree-sitter");
  const tsModule = require("tree-sitter-typescript");
  tsLanguage = tsModule.typescript || tsModule;
  // console.log('Tree-sitter loaded successfully');
} catch (_err) {
  // console.error('Failed to load Tree-sitter:', err);
}

export interface CallGraphContext {
  symbols: SymbolIndex;
  deps: DependencyGraph;
  allFiles: Set<string>;
}

export function extractFileCalls(
  filePath: string,
  content: string,
  context: CallGraphContext,
): CallGraph {
  const fileCallGraph: CallGraph = {};

  if (!Parser || !tsLanguage || !filePath.match(/\.(ts|tsx|js|jsx)$/)) {
    return fileCallGraph;
  }

  const parser = new Parser();
  parser.setLanguage(tsLanguage);
  const tree = parser.parse(content);

  let currentScope: string | null = null; // file:symbol

  // biome-ignore lint/suspicious/noExplicitAny: tree-sitter AST node has no TS type
  function visit(node: any) {
    // 1. Track definition scope
    let newScopeDefined = false;
    if (
      node.type === "function_declaration" ||
      node.type === "method_definition"
    ) {
      const nameNode = node.childForFieldName("name");
      if (nameNode) {
        const name = nameNode.text;
        currentScope = `${filePath}:${name}`;
        if (!fileCallGraph[currentScope]) {
          fileCallGraph[currentScope] = { calls: [], calledBy: [] };
        }
        newScopeDefined = true;
      }
    } else if (node.type === "class_declaration") {
      const nameNode = node.childForFieldName("name");
      if (nameNode) {
        // Classes can call things in their constructor or field initializers,
        // but usually we care about methods. We'll set scope to class temporarily.
        const name = nameNode.text;
        currentScope = `${filePath}:${name}`;
        if (!fileCallGraph[currentScope]) {
          fileCallGraph[currentScope] = { calls: [], calledBy: [] };
        }
        newScopeDefined = true;
      }
    }

    // 2. Find calls
    if (node.type === "call_expression") {
      const functionNode = node.childForFieldName("function");
      if (functionNode && currentScope) {
        const callEntry = resolveCall(functionNode, filePath, context);
        if (callEntry) {
          fileCallGraph[currentScope].calls.push(callEntry);
        }
      }
    }

    // Recurse
    for (let i = 0; i < node.childCount; i++) {
      visit(node.child(i));
    }

    // Restore scope if we defined one here
    if (newScopeDefined) {
      // This is a simplification. Real scope tracking would need a stack.
      // But for top-level functions/methods it's mostly okay.
      currentScope = null;
    }
  }

  visit(tree.rootNode);
  return fileCallGraph;
}

function resolveCall(
  // biome-ignore lint/suspicious/noExplicitAny: tree-sitter AST node has no TS type
  node: any,
  currentFile: string,
  context: CallGraphContext,
): CallGraphEntry | null {
  const text = node.text;

  // Simple function call: foo()
  if (node.type === "identifier") {
    const name = text;
    // Heuristic 1: Is it in the same file?
    const _sameFileId = `${currentFile}:${name}`;
    if (context.symbols[name] && context.symbols[name].file === currentFile) {
      return { name, file: currentFile, line: context.symbols[name].startLine };
    }

    // Heuristic 2: Is it imported?
    const fileDeps = context.deps[currentFile];
    if (fileDeps) {
      for (const imp of fileDeps.imports) {
        if (imp.symbols.includes(name)) {
          // Found the file!
          const _targetSymbol = `${imp.file}:${name}`;
          // We might not have the exact line here without more lookup,
          // but we have the file.
          return { name, file: imp.file };
        }
      }
    }

    return { name };
  }

  // Method call: obj.method()
  if (node.type === "member_expression") {
    const propertyNode = node.childForFieldName("property");
    if (propertyNode) {
      const methodName = propertyNode.text;
      // Without type inference, we can only guess.
      // We return the method name at least.
      return { name: methodName };
    }
  }

  return null;
}

export function buildGlobalCallGraph(partials: CallGraph[]): CallGraph {
  const global: CallGraph = {};

  // 1. Merge calls
  for (const partial of partials) {
    for (const [callerId, data] of Object.entries(partial)) {
      if (!global[callerId]) {
        global[callerId] = { calls: [], calledBy: [] };
      }
      global[callerId].calls.push(...data.calls);
    }
  }

  // 2. Compute calledBy (in-edges)
  for (const [callerId, data] of Object.entries(global)) {
    for (const call of data.calls) {
      if (call.file) {
        const calleeId = `${call.file}:${call.name}`;
        if (!global[calleeId]) {
          global[calleeId] = { calls: [], calledBy: [] };
        }
        if (!global[calleeId].calledBy.includes(callerId)) {
          global[calleeId].calledBy.push(callerId);
        }
      }
    }
  }

  return global;
}

import type { AiMemoryConfig, Chunk } from "../core/types";
import { hashContent } from "./hasher";

/**
 * Chunking sliding window.
 */

export function chunkBySlidingWindow(
  filePath: string,
  lines: string[],
  lineOffset: number,
  config: AiMemoryConfig,
  symbol?: string,
): Chunk[] {
  const chunks: Chunk[] = [];
  const overlap = Math.max(1, Math.floor(config.maxChunkLines * 0.1));
  let i = 0;

  while (i < lines.length) {
    const slice = lines.slice(i, i + config.maxChunkLines);
    const content = slice.join("\n");
    if (content.trim().length > 0) {
      const startLine = lineOffset + i;
      const endLine = lineOffset + i + slice.length - 1;
      chunks.push(makeChunk(filePath, content, startLine, endLine, symbol));
    }
    if (i + config.maxChunkLines >= lines.length) break;
    i += config.maxChunkLines - overlap;
  }

  return chunks;
}

function makeChunk(
  file: string,
  content: string,
  start: number,
  end: number,
  symbol?: string,
): Chunk {
  const id = hashContent(file + "\n" + content);
  return { id, file, start, end, symbol, content };
}

import type { AiMemoryConfig, Chunk } from "../core/types";
import type { ParsedSymbol } from "./parser";
import { buildClassHeaders } from "./classHeader";
import { hashContent } from "./hasher";
import { chunkBySlidingWindow } from "./chunkBySlidingWindow";

/**
 * Chunking basato su simboli.
 */

export function chunkBySymbols(
  filePath: string,
  lines: string[],
  symbols: ParsedSymbol[],
  config: AiMemoryConfig,
): Chunk[] {
  const chunks: Chunk[] = [];
  const classHeaders = buildClassHeaders(lines, symbols);

  const bounded = symbols
    .filter((s) => s.endLine >= s.startLine)
    .sort((a, b) => a.startLine - b.startLine);

  // Include the file header (imports, top-level declarations) as its own chunk
  const firstSymbolStart = bounded[0]?.startLine ?? lines.length + 1;
  if (firstSymbolStart > 5) {
    const headerLines = lines.slice(0, firstSymbolStart - 1);
    const headerContent = headerLines.join("\n").trim();
    if (headerContent.length > 30) {
      chunks.push(makeChunk(filePath, headerContent, 1, firstSymbolStart - 1));
    }
  }

  for (const sym of bounded) {
    const symLines = lines.slice(sym.startLine - 1, sym.endLine);
    let symContent = symLines.join("\n");
    if (sym.type === "method" && sym.parent) {
      const header = classHeaders.get(sym.parent);
      if (header) {
        symContent = `${header}\n\n  // ...\n\n${symLines.join("\n")}`;
      }
    }
    if (
      symLines.length > config.maxChunkLines ||
      symContent.length > config.maxChunkChars
    ) {
      const subChunks = chunkBySlidingWindow(
        filePath,
        symLines,
        sym.startLine,
        config,
        sym.name,
      );
      chunks.push(...subChunks);
    } else {
      chunks.push(
        makeChunk(filePath, symContent, sym.startLine, sym.endLine, sym.name),
      );
    }
  }

  // Any trailing content after the last symbol
  const lastEnd = bounded[bounded.length - 1]?.endLine ?? 0;
  if (lastEnd < lines.length) {
    const tailContent = lines.slice(lastEnd).join("\n").trim();
    if (tailContent.length > 50) {
      chunks.push(makeChunk(filePath, tailContent, lastEnd + 1, lines.length));
    }
  }

  return chunks;
}

function makeChunk(
  file: string,
  content: string,
  start: number,
  end: number,
  symbol?: string,
): Chunk {
  const id = hashContent(file + "\n" + content);
  return { id, file, start, end, symbol, content };
}

import type { AiMemoryConfig, Chunk } from "../core/types";
import type { ParsedSymbol } from "./parser";
import { selectChunkingStrategy } from "./strategy";
import { chunkBySymbols } from "./chunkBySymbols";
import { chunkBySlidingWindow } from "./chunkBySlidingWindow";

/**
 * Splits a file into chunks suitable for embedding and retrieval.
 *
 * Strategy:
 *  1. If tree-sitter gave us symbol boundaries with real line ranges,
 *     create one chunk per symbol (split further if too large).
 *  2. Otherwise fall back to a sliding window chunker.
 *
 * Chunk IDs are derived from file path + content hash, so unchanged code
 * keeps the same ID across re-indexing — enabling embedding cache reuse.
 */

export function chunkFile(
  filePath: string,
  content: string,
  symbols: ParsedSymbol[],
  config: AiMemoryConfig,
): Chunk[] {
  const lines = content.split("\n");
  const strategy = selectChunkingStrategy(symbols);
  if (strategy === "symbol") {
    return chunkBySymbols(filePath, lines, symbols, config);
  }
  return chunkBySlidingWindow(filePath, lines, 1, config);
}

export function buildClassHeaders(
  lines: string[],
  symbols: ParsedSymbol[],
): Map<string, string> {
  const headers = new Map<string, string>();
  const firstMethodLine = new Map<string, number>();
  for (const sym of symbols) {
    if (sym.type === "method" && sym.parent) {
      const existing = firstMethodLine.get(sym.parent);
      if (existing === undefined || sym.startLine < existing) {
        firstMethodLine.set(sym.parent, sym.startLine);
      }
    }
  }
  for (const cls of symbols) {
    if (cls.type !== "class" || cls.endLine <= cls.startLine) continue;
    const firstMethod = firstMethodLine.get(cls.name);
    if (!firstMethod) continue;
    const headerEndLine = Math.min(
      firstMethod - 1,
      cls.startLine + CLASS_HEADER_MAX_LINES - 1,
    );
    const headerLines = lines.slice(cls.startLine - 1, headerEndLine);
    while (headerLines.length > 0 && !headerLines[headerLines.length - 1].trim()) {
      headerLines.pop();
    }
    if (headerLines.length >= 2) {
      headers.set(cls.name, headerLines.join("\n"));
    }
  }
  return headers;
}

import fs from "fs";
import path from "path";
import type {
  DependencyGraph,
  FileDependencies,
  ImportEntry,
} from "../core/types";

// ─── tsconfig path alias resolution ──────────────────────────────────────────

export interface TsPathAlias {
  /** The literal prefix before the wildcard, e.g. "@/" for pattern "@/*" */
  prefix: string;
  /** Replacement targets, e.g. ["src/*"] */
  targets: string[];
  /** baseUrl from compilerOptions (relative to project root), e.g. "." */
  baseUrl: string;
}

export function loadTsPathAliases(rootDir: string): TsPathAlias[] {
  const candidates = [
    "tsconfig.json",
    "tsconfig.base.json",
    "tsconfig.node.json",
  ];

  for (const name of candidates) {
    const tsConfigPath = path.join(rootDir, name);
    try {
      const raw = fs.readFileSync(tsConfigPath, "utf-8");
      // tsconfig allows // comments — strip them before JSON.parse
      const stripped = raw
        .replace(/\/\/[^\n]*/g, "")
        .replace(/\/\*[\s\S]*?\*\//g, "");
      const config = JSON.parse(stripped);
      const opts = config.compilerOptions ?? {};
      const baseUrl: string = opts.baseUrl ?? ".";
      const paths: Record<string, string[]> = opts.paths ?? {};

      if (Object.keys(paths).length === 0) continue;

      return Object.entries(paths).map(([pattern, targets]) => ({
        prefix: pattern.replace(/\*$/, ""),
        targets,
        baseUrl,
      }));
    } catch {
      // file missing or invalid — try next candidate
    }
  }

  return [];
}

function resolveAlias(
  source: string,
  aliases: TsPathAlias[],
  allFiles: Set<string>,
): string | null {
  for (const { prefix, targets, baseUrl } of aliases) {
    if (!source.startsWith(prefix)) continue;
    const rest = source.slice(prefix.length);

    for (const target of targets) {
      const resolved = target.replace("*", rest);
      const base = path.normalize(path.join(baseUrl, resolved));

      const extCandidates = ["", ".ts", ".tsx", ".js", ".jsx"];
      for (const ext of extCandidates) {
        const candidate = path.normalize(base + ext);
        if (allFiles.has(candidate)) return candidate;
      }
      for (const idx of ["index.ts", "index.tsx", "index.js"]) {
        const candidate = path.join(base, idx);
        if (allFiles.has(candidate)) return candidate;
      }
    }
  }
  return null;
}

interface RawImport {
  source: string;
  symbols: string[];
}

function extractRawImports(content: string): RawImport[] {
  const results: RawImport[] = [];

  // Static imports
  let m: RegExpExecArray | null;
  STATIC_IMPORT_RE.lastIndex = 0;
  while ((m = STATIC_IMPORT_RE.exec(content)) !== null) {
    const namedGroup = m[1]; // content inside { }
    const defaultName = m[2]; // default import identifier
    const source = m[3];
    if (!source) continue;

    const symbols: string[] = [];
    if (namedGroup) symbols.push(...parseNamedImports(namedGroup));
    if (defaultName && /^\w+$/.test(defaultName)) symbols.push(defaultName);

    results.push({ source, symbols });
  }

  // Re-exports
  EXPORT_FROM_RE.lastIndex = 0;
  while ((m = EXPORT_FROM_RE.exec(content)) !== null) {
    const namedGroup = m[1];
    const source = m[2];
    if (!source) continue;
    const symbols = namedGroup ? parseNamedImports(namedGroup) : [];
    results.push({ source, symbols });
  }

  // Dynamic imports / require
  DYNAMIC_RE.lastIndex = 0;
  while ((m = DYNAMIC_RE.exec(content)) !== null) {
    const source = m[1];
    if (source) results.push({ source, symbols: [] });
  }

  return results;
}

function parseNamedImports(raw: string): string[] {
  return raw
    .split(",")
    .map((s) =>
      s
        .trim()
        .replace(/^type\s+/, "")
        .split(/\s+as\s+/)[0]
        .trim(),
    )
    .filter((s) => s.length > 0 && /^\w+$/.test(s));
}

function isRelative(source: string): boolean {
  return source.startsWith("./") || source.startsWith("../");
}

function resolveImport(
  source: string,
  importerDir: string, // directory of the importing file (relative to root)
  allFiles: Set<string>,
): string | null {
  // Compute the base path relative to project root
  const base = path.normalize(path.join(importerDir, source));

  // Candidate extensions to try (in priority order)
  const extCandidates = ["", ".ts", ".tsx", ".js", ".jsx", ".mts", ".cts"];
  // If source already has an extension (e.g. .js in "import './foo.js'"),
  // also try swapping it to .ts (common in TypeScript projects)
  const sourceExt = path.extname(source);
  if (sourceExt === ".js") extCandidates.unshift(base.slice(0, -3) + ".ts");
  if (sourceExt === ".mjs") extCandidates.unshift(base.slice(0, -4) + ".mts");

  for (const ext of extCandidates) {
    const candidate =
      typeof ext === "string" && ext.startsWith("/")
        ? ext // already absolute-looking resolved path
        : base + ext;
    const norm = path.normalize(candidate);
    if (allFiles.has(norm)) return norm;
  }

  // Try as directory index
  const indexCandidates = ["index.ts", "index.tsx", "index.js", "index.jsx"];
  for (const idx of indexCandidates) {
    const candidate = path.join(base, idx);
    if (allFiles.has(candidate)) return candidate;
  }

  return null;
}

export function extractFileImports(
  relativePath: string,
  content: string,
  allFiles: Set<string>,
  aliases: TsPathAlias[] = [],
): ImportEntry[] {
  const ext = path.extname(relativePath).slice(1).toLowerCase();
  if (!JS_TS_EXTS.has(ext)) return []; // only JS/TS files have parseable imports

  const importerDir = path.dirname(relativePath);
  const raw = extractRawImports(content);

  // Deduplicate by resolved file path, merging symbols
  const resolved = new Map<string, Set<string>>();

  for (const { source, symbols } of raw) {
    let resolvedPath: string | null = null;
    if (isRelative(source)) {
      resolvedPath = resolveImport(source, importerDir, allFiles);
    } else if (aliases.length > 0) {
      resolvedPath = resolveAlias(source, aliases, allFiles);
    }
    if (!resolvedPath || resolvedPath === relativePath) continue; // skip self-imports

    const existing = resolved.get(resolvedPath) ?? new Set<string>();
    for (const s of symbols) existing.add(s);
    resolved.set(resolvedPath, existing);
  }

  return Array.from(resolved.entries()).map(([file, syms]) => ({
    file,
    symbols: Array.from(syms).sort(),
  }));
}

export function updateDependencyGraph(
  prevGraph: DependencyGraph,
  changedFiles: Map<string, string>, // relativePath → content (new/changed files)
  deletedFiles: Set<string>,
  allFiles: Set<string>,
  aliases: TsPathAlias[] = [],
): DependencyGraph {
  const graph: DependencyGraph = {};

  // Carry forward unchanged entries
  for (const [file, deps] of Object.entries(prevGraph)) {
    if (!deletedFiles.has(file) && !changedFiles.has(file)) {
      graph[file] = deps;
    }
  }

  // Re-process changed/new files
  for (const [relativePath, content] of changedFiles) {
    const imports = extractFileImports(relativePath, content, allFiles, aliases);
    if (imports.length > 0) {
      graph[relativePath] = { imports };
    }
  }

  return graph;
}

export function computeImportedBy(
  graph: DependencyGraph,
): Map<string, string[]> {
  const importedBy = new Map<string, string[]>();

  for (const [file, { imports }] of Object.entries(graph)) {
    for (const imp of imports) {
      const list = importedBy.get(imp.file) ?? [];
      list.push(file);
      importedBy.set(imp.file, list);
    }
  }

  return importedBy;
}

export function getTransitiveDeps(
  startFile: string,
  graph: DependencyGraph,
  depth = 1,
): Map<string, number> {
  const visited = new Map<string, number>(); // file → distance
  const queue: Array<[string, number]> = [[startFile, 0]];
  let head = 0;

  while (head < queue.length) {
    const [file, dist] = queue[head++];
    if (dist > depth) break;

    for (const imp of graph[file]?.imports ?? []) {
      if (!visited.has(imp.file)) {
        visited.set(imp.file, dist + 1);
        queue.push([imp.file, dist + 1]);
      }
    }
  }

  return visited;
}

export function detectCycles(graph: DependencyGraph): string[][] {
  const WHITE = 0,
    GRAY = 1,
    BLACK = 2;
  const color = new Map<string, number>();
  const cycles: string[][] = [];

  function dfs(node: string, stack: string[]): void {
    color.set(node, GRAY);
    stack.push(node);

    for (const imp of graph[node]?.imports ?? []) {
      const c = color.get(imp.file) ?? WHITE;
      if (c === GRAY) {
        const idx = stack.indexOf(imp.file);
        if (idx !== -1) cycles.push([...stack.slice(idx), imp.file]);
      } else if (c === WHITE) {
        dfs(imp.file, stack);
      }
      if (cycles.length >= 5) break; // cap early
    }

    stack.pop();
    color.set(node, BLACK);
  }

  for (const file of Object.keys(graph)) {
    if ((color.get(file) ?? WHITE) === WHITE) dfs(file, []);
    if (cycles.length >= 5) break;
  }

  // Deduplicate: same cycle can be discovered starting from different nodes
  const seen = new Set<string>();
  return cycles.filter((cycle) => {
    const key = [...cycle].sort().join("|");
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

export function graphStats(graph: DependencyGraph): {
  totalFiles: number;
  totalEdges: number;
  mostImported: Array<{ file: string; count: number }>;
} {
  const importedByCount = new Map<string, number>();
  let totalEdges = 0;

  for (const { imports } of Object.values(graph)) {
    totalEdges += imports.length;
    for (const imp of imports) {
      importedByCount.set(imp.file, (importedByCount.get(imp.file) ?? 0) + 1);
    }
  }

  const mostImported = Array.from(importedByCount.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([file, count]) => ({ file, count }));

  return { totalFiles: Object.keys(graph).length, totalEdges, mostImported };
}

import crypto from "crypto";
import fs from "fs";

/**
 * Computes the SHA-256 hash of a file's content.
 * Used for change detection during incremental indexing.
 */

export function hashFile(filePath: string): string {
  const content = fs.readFileSync(filePath);
  return crypto.createHash("sha256").update(content).digest("hex");
}

export function hashContent(content: string): string {
  return crypto
    .createHash("sha256")
    .update(content, "utf-8")
    .digest("hex")
    .slice(0, 16);
}

import type { SymbolIndex } from "../core/types";

// ─── tree-sitter (optional) ───────────────────────────────────────────────────
// tree-sitter native bindings are in optionalDependencies.
// If they fail to build (some CI environments, ARM, etc.) we fall back to regex.

let TreeSitterParser: (new () => TreeSitterParserInstance) | null = null;
let tsLanguage: unknown = null;
let tsxLanguage: unknown = null;
let jsLanguage: unknown = null;

interface TreeSitterParserInstance {
  setLanguage(lang: unknown): void;
  parse(src: string): { rootNode: TreeNode };
}

interface TreeNode {
  type: string;
  text: string;
  startPosition: { row: number; column: number };
  endPosition: { row: number; column: number };
  children: TreeNode[];
  namedChildren: TreeNode[];
  childForFieldName(name: string): TreeNode | null;
}

export interface ParsedSymbol {
  name: string;
  type:
    | "function"
    | "class"
    | "method"
    | "interface"
    | "type"
    | "constant"
    | "variable";
  startLine: number;
  endLine: number;
  exported: boolean;
  parent?: string;
}

export function parseSymbols(
  filePath: string,
  content: string,
): ParsedSymbol[] {
  const ext = filePath.split(".").pop()?.toLowerCase() ?? "";

  if (TreeSitterParser) {
    try {
      if (ext === "ts") return parseWithTreeSitter(content, tsLanguage);
      if (ext === "tsx") return parseWithTreeSitter(content, tsxLanguage);
      if (ext === "js" || ext === "jsx")
        return parseWithTreeSitter(content, jsLanguage);
    } catch {
      // fall through to regex
    }
  }

  return parseWithRegex(content);
}

export function buildSymbolIndex(
  filePath: string,
  symbols: ParsedSymbol[],
): SymbolIndex {
  const index: SymbolIndex = {};
  for (const sym of symbols) {
    index[sym.name] = {
      type: sym.type,
      file: filePath,
      startLine: sym.startLine,
      endLine: sym.endLine,
      exported: sym.exported,
      parent: sym.parent,
    };
  }
  return index;
}

function parseWithTreeSitter(
  content: string,
  language: unknown,
): ParsedSymbol[] {
  if (!TreeSitterParser || !language) return parseWithRegex(content);

  const parser = new TreeSitterParser();
  parser.setLanguage(language);
  const tree = parser.parse(content);
  const symbols: ParsedSymbol[] = [];
  visitNode(tree.rootNode, symbols, null, false);
  return symbols;
}

function visitNode(
  node: TreeNode,
  out: ParsedSymbol[],
  parentClass: string | null,
  insideExport: boolean,
): void {
  switch (node.type) {
    case "export_statement": {
      // Recurse into the declaration, marking it as exported
      for (const child of node.namedChildren) {
        visitNode(child, out, parentClass, true);
      }
      return;
    }

    case "function_declaration":
    case "generator_function_declaration": {
      const name = node.childForFieldName("name")?.text;
      if (name) {
        out.push({
          name: parentClass ? `${parentClass}.${name}` : name,
          type: "function",
          startLine: node.startPosition.row + 1,
          endLine: node.endPosition.row + 1,
          exported: insideExport,
          parent: parentClass ?? undefined,
        });
      }
      // Don't recurse into function bodies for top-level symbol collection
      return;
    }

    case "class_declaration": {
      const name = node.childForFieldName("name")?.text;
      if (name) {
        out.push({
          name,
          type: "class",
          startLine: node.startPosition.row + 1,
          endLine: node.endPosition.row + 1,
          exported: insideExport,
        });
        // Extract methods from class body
        const body = node.childForFieldName("body");
        if (body) {
          for (const child of body.namedChildren) {
            visitNode(child, out, name, false);
          }
        }
      }
      return;
    }

    case "method_definition": {
      const name = node.childForFieldName("name")?.text;
      if (name && parentClass && name !== "constructor") {
        out.push({
          name: `${parentClass}.${name}`,
          type: "method",
          startLine: node.startPosition.row + 1,
          endLine: node.endPosition.row + 1,
          exported: false,
          parent: parentClass,
        });
      }
      return;
    }

    case "lexical_declaration":
    case "variable_declaration": {
      // const/let/var — check if the RHS is a function
      for (const child of node.namedChildren) {
        if (child.type === "variable_declarator") {
          const name = child.childForFieldName("name")?.text;
          const value = child.childForFieldName("value");
          if (!name) continue;

          if (
            value &&
            (value.type === "arrow_function" || value.type === "function")

        if (child.type === "variable_declarator") {
          const name = child.childForFieldName("name")?.text;
          const value = child.childForFieldName("value");
          if (!name) continue;

          if (
            value &&
            (value.type === "arrow_function" || value.type === "function")
          ) {
            out.push({
              name,
              type: "function",
              startLine: node.startPosition.row + 1,
              endLine: node.endPosition.row + 1,
              exported: insideExport,
            });
          } else if (insideExport && value) {
            out.push({
              name,
              type: "constant",
              startLine: node.startPosition.row + 1,
              endLine: node.endPosition.row + 1,
              exported: true,
            });
          }
        }
      }
      return;
    }

    case "interface_declaration": {
      const name = node.childForFieldName("name")?.text;
      if (name) {
        out.push({
          name,
          type: "interface",
          startLine: node.startPosition.row + 1,
          endLine: node.endPosition.row + 1,
          exported: insideExport,
        });
      }
      return;
    }

    case "type_alias_declaration": {
      const name = node.childForFieldName("name")?.text;
      if (name) {
        out.push({
          name,
          type: "type",
          startLine: node.startPosition.row + 1,
          endLine: node.endPosition.row + 1,
          exported: insideExport,
        });
      }
      return;
    }

    default:
      // Recurse into other top-level constructs (namespaces, modules, etc.)
      for (const child of node.namedChildren) {
        visitNode(child, out, parentClass, insideExport);
      }
  }
}

function findEndLine(lines: string[], startIndex: number): number {
  let depth = 0;
  let braceFound = false;

  for (let i = startIndex; i < lines.length; i++) {
    for (const ch of lines[i]) {
      if (ch === "{") {
        depth++;
        braceFound = true;
      } else if (ch === "}") {
        depth--;
        if (braceFound && depth === 0) return i + 1; // 1-indexed
      }
    }
  }

  // No braces found — use indentation heuristic (Python, YAML-style, etc.)
  if (!braceFound) {
    const baseIndent = lines[startIndex].match(/^(\s*)/)?.[1].length ?? 0;
    for (let i = startIndex + 1; i < lines.length; i++) {
      const line = lines[i];
      if (!line.trim()) continue; // skip blank lines
      const indent = line.match(/^(\s*)/)?.[1].length ?? 0;
      if (indent <= baseIndent) return i; // i is 0-based next-block line → 1-based prev line
    }
    return lines.length; // EOF
  }

  return startIndex + 1; // fallback: same as start line
}

function parseWithRegex(content: string): ParsedSymbol[] {
  const symbols: ParsedSymbol[] = [];
  const lines = content.split("\n");

  const patterns: Array<{
    re: RegExp;
    type: ParsedSymbol["type"];
    exportGroup?: boolean;
  }> = [
    // TypeScript/JavaScript
    {
      re: /^(export\s+)?(async\s+)?function\s+(\w+)\s*[(<]/,
      type: "function",
      exportGroup: true,
    },
    {
      re: /^(export\s+)?(const|let)\s+(\w+)\s*=\s*(async\s+)?(\([^)]*\)|[^=])\s*=>/,
      type: "function",
      exportGroup: true,
    },
    {
      re: /^(export\s+)?(abstract\s+)?class\s+(\w+)/,
      type: "class",
      exportGroup: true,
    },
    {
      re: /^(export\s+)?interface\s+(\w+)/,
      type: "interface",
      exportGroup: true,
    },
    { re: /^(export\s+)?type\s+(\w+)\s*=/, type: "type", exportGroup: true },
    // Python
    { re: /^(async\s+)?def\s+(\w+)\s*\(/, type: "function" },
    { re: /^class\s+(\w+)(?:\s*:|\s*\()/, type: "class" },
    // Rust
    {
      re: /^(pub\s+)?(async\s+)?fn\s+(\w+)\s*[(<]/,
      type: "function",
      exportGroup: true,
    },
    { re: /^(pub\s+)?(struct|enum)\s+(\w+)/, type: "class", exportGroup: true },
    // Go
    { re: /^func\s+(\w+)\s*\(/, type: "function" },
    { re: /^type\s+(\w+)\s+(struct|interface)/, type: "class" },
  ];

  lines.forEach((line, i) => {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("//") || trimmed.startsWith("#")) return;

    for (const { re, type } of patterns) {
      const m = trimmed.match(re);
      if (m) {
        // Heuristic: find the captured group that looks like an identifier
        const name = m.slice(1).find((g) => g && /^\w+$/.test(g));
        if (
          name &&
          name !== "async" &&
          name !== "pub" &&
          name !== "abstract" &&
          name !== "struct" &&
          name !== "enum" &&
          name !== "const" &&
          name !== "let"
        ) {
          symbols.push({
            name,
            type,
            startLine: i + 1,
            endLine: findEndLine(lines, i),
            exported:
              trimmed.startsWith("export") ||
              trimmed.startsWith("pub ") ||
              trimmed.startsWith("pub("),
          });
          break;
        }
      }
    }
  });

              trimmed.startsWith("pub ") ||
              trimmed.startsWith("pub("),
          });
          break;
        }
      }
    }
  });

  return symbols;
}

export interface ScannedFile {
  absolutePath: string;
  relativePath: string;
  /** Lowercase extension without leading dot */
  extension: string;
}

export async function scanRepository(
  config: AiMemoryConfig,
): Promise<ScannedFile[]> {
  const entries = await fg(config.include, {
    cwd: config.rootDir,
    ignore: config.exclude,
    dot: false,
    absolute: false,
    followSymbolicLinks: false,
    onlyFiles: true,
    // Return in consistent order for reproducible hashing
    caseSensitiveMatch: true,
  });

  return entries
    .sort() // reproducible order across machines
    .map((relativePath) => ({
      absolutePath: path.join(config.rootDir, relativePath),
      relativePath,
      extension: path.extname(relativePath).slice(1).toLowerCase(),
    }));
}

export function selectChunkingStrategy(symbols: ParsedSymbol[]): "symbol" | "sliding" {
  return symbols.some((s) => s.endLine >= s.startLine) ? "symbol" : "sliding";
}

import path from "path";

// Common test file suffixes and directory patterns
const TEST_SUFFIXES = [".test.ts", ".test.tsx", ".test.js", ".test.jsx",
                       ".spec.ts", ".spec.tsx", ".spec.js", ".spec.jsx"];
const TEST_DIRS = ["__tests__", "test", "tests", "spec", "__spec__"];

/**
 * Returns all test files in the project that are likely to test `relPath`.
 *
 * Two strategies (both applied, results deduplicated):
 *  1. Convention-based: look for sibling files with `.test.*` / `.spec.*`
 *     suffix, and for the same basename inside common test directories.
 *  2. Import-based: any file whose path contains "test" or "spec" that is
 *     known to import `relPath` (via the dependency graph).
 *
 * @param relPath       The source file to find tests for (project-relative)
 * @param allFiles      All known project-relative file paths
 * @param importedBy    Optional map of file → set of files that import it
 */

export function findTestFiles(
  relPath: string,
  allFiles: Iterable<string>,
  importedBy?: Map<string, string[]>,
): string[] {
  const allFilesSet = new Set(allFiles);
  const found = new Set<string>();

  const dir = path.dirname(relPath);
  const base = path.basename(relPath);
  // Strip known source extension to get the bare stem (e.g. "foo")
  const stem = base.replace(/\.(ts|tsx|js|jsx|mts|cts|mjs|cjs)$/, "");

  // Strategy 1a: sibling test files in the same directory
  for (const suffix of TEST_SUFFIXES) {
    const candidate = path.join(dir, stem + suffix);
    if (allFilesSet.has(candidate)) found.add(candidate);
  }

  // Strategy 1b: same stem inside adjacent test directories
  for (const testDir of TEST_DIRS) {
    for (const suffix of TEST_SUFFIXES) {
      // e.g. src/__tests__/foo.test.ts
      const inSiblingDir = path.join(dir, testDir, stem + suffix);
      if (allFilesSet.has(inSiblingDir)) found.add(inSiblingDir);

      // e.g. __tests__/foo.test.ts (root-level test dir)
      const inRootDir = path.join(testDir, stem + suffix);
      if (allFilesSet.has(inRootDir)) found.add(inRootDir);
    }
    // Bare filename without suffix (e.g. __tests__/foo.ts)
    for (const ext of [".ts", ".tsx", ".js", ".jsx"]) {
      const inSiblingDir = path.join(dir, testDir, stem + ext);
      if (allFilesSet.has(inSiblingDir)) found.add(inSiblingDir);
    }
  }

  // Strategy 2: import-based — files that import relPath and look like tests
  if (importedBy) {
    const importers = importedBy.get(relPath) ?? [];
    for (const importer of importers) {
      if (/[./](test|spec)[./]|\.test\.|\.spec\./.test(importer)) {
        found.add(importer);
      }
    }
  }

  return Array.from(found).sort();
}

import type { TodoAnnotation } from "../core/types";

// Matches: // TODO: ..., # FIXME ..., /* HACK ... */, etc.
// Captures the keyword and the rest of the comment text on that line.
const TODO_RE = /\b(TODO|FIXME|HACK|XXX)\b[:\s]*(.*)/i;

/**
 * Scans the lines of a source file and returns all TODO/FIXME/HACK/XXX
 * annotations found in comments or inline text.
 *
 * Line numbers are 1-based to match editor conventions.
 */

export function extractTodos(
  relativePath: string,
  content: string,
): TodoAnnotation[] {
  const todos: TodoAnnotation[] = [];
  const lines = content.split("\n");

  for (let i = 0; i < lines.length; i++) {
    const match = lines[i].match(TODO_RE);
    if (match) {
      todos.push({
        file: relativePath,
        line: i + 1,
        type: match[1].toUpperCase() as TodoAnnotation["type"],
        text: match[2].trim(),
      });
    }
  }

  return todos;
}

