import type { Chunk, SearchResult, SymbolIndex } from "../core/types";

/**
 * BM25 implementation for high-precision keyword search.
 */

const K1 = 1.5;
const B = 0.75;

// --- In-Memory Cache for BM25 (vital for chat session performance) ---

interface BM25Cache {
  chunkIdsHash: string;
  docTokens: string[][];
  tfMaps: Map<string, number>[];
  dfMap: Map<string, number>;
  avgdl: number;
  N: number;
}

function computeHash(chunks: Chunk[]): string {
  if (chunks.length === 0) return "";
  const chunkIds = chunks.map((c) => c.id).sort();
  return chunkIds.join("|");
}

export function computeBM25Scores(
  query: string,
  chunks: Chunk[],
  symbols: SymbolIndex,
  topK = 10,
): SearchResult[] {
  // 1. Tokenize query
  const queryTerms = query
    .toLowerCase()
    .split(/[\s\W]+/)
    .filter((t) => t.length >= 2); // Slightly more inclusive than current TF search

  if (queryTerms.length === 0) return [];

  const N = chunks.length;
  if (N === 0) return [];

  const currentHash = computeHash(chunks);

  // 2. Tokenize docs and compute stats (with CACHING)
  if (!bm25Cache || bm25Cache.chunkIdsHash !== currentHash) {
    // Cache miss: compute everything
    const docTokens: string[][] = [];
    const tfMaps: Map<string, number>[] = [];
    let totalLen = 0;
    const dfMap = new Map<string, number>();

    for (const chunk of chunks) {
      const tokens = chunk.content.toLowerCase().split(/[\s\W]+/);
      docTokens.push(tokens);
      totalLen += tokens.length;

      const tfMap = new Map<string, number>();
      for (const token of tokens) {
        tfMap.set(token, (tfMap.get(token) || 0) + 1);
      }
      tfMaps.push(tfMap);

      // Unique tokens for DF calculation
      for (const token of tfMap.keys()) {
        dfMap.set(token, (dfMap.get(token) || 0) + 1);
      }
    }

    bm25Cache = {
      chunkIdsHash: currentHash,
      docTokens,
      tfMaps,
      dfMap,
      avgdl: totalLen / N,
      N,
    };
  }

  const { docTokens, tfMaps, dfMap, avgdl } = bm25Cache;

  // 3. Compute IDF for query terms
  const idfMap = new Map<string, number>();
  for (const term of queryTerms) {
    const df = dfMap.get(term) || 0;
    // Standard BM25 IDF: ln((N - df + 0.5) / (df + 0.5) + 1)
    const idf = Math.log((N - df + 0.5) / (df + 0.5) + 1);
    idfMap.set(term, Math.max(0, idf)); // IDF can be negative if term is in > half docs
  }

  // 4. Compute BM25 scores
  const results: SearchResult[] = chunks.map((chunk, i) => {
    const tokens = docTokens[i];
    const tfMap = tfMaps[i];
    const dl = tokens.length;
    let score = 0;

    for (const term of queryTerms) {
      const tf = tfMap.get(term) || 0;
      const idf = idfMap.get(term) || 0;

      // BM25 Formula: IDF * (tf * (k1 + 1)) / (tf + k1 * (1 - b + b * (dl / avgdl)))
      const numerator = tf * (K1 + 1);
      const denominator = tf + K1 * (1 - B + B * (dl / avgdl));
      score += idf * (numerator / denominator);

    for (const term of queryTerms) {
      const tf = tfMap.get(term) || 0;
      const idf = idfMap.get(term) || 0;

      // BM25 Formula: IDF * (tf * (k1 + 1)) / (tf + k1 * (1 - b + b * (dl / avgdl)))
      const numerator = tf * (K1 + 1);
      const denominator = tf + K1 * (1 - B + B * (dl / avgdl));
      score += idf * (numerator / denominator);
    }

    // Bonus: exact symbol match
    if (chunk.symbol) {
      const symLower = chunk.symbol.toLowerCase();
      if (queryTerms.some((t) => symLower.includes(t))) {
        // Boost for keyword match in symbol name
        score *= 1.5;
      }
      if (queryTerms.some((t) => symLower === t)) {
        // Higher boost for exact identifier match
        score *= 2.0;
      }
    }

    const symbol = chunk.symbol ? symbols[chunk.symbol] : undefined;
    return { chunk, score, symbol };
  });

  // 5. Sort and return
  return results
    .filter((r) => r.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, topK);
}

import type {
  CallGraph,
  DependencyGraph,
  FileSummaryIndex,
  SearchResult,
} from "../core/types";
import { computeImportedBy } from "../indexer/deps";
import { extractSignature, getDisplayTier, HIGH_CODE_LINES } from "./signature";

export interface FormatOptions {
  format: OutputFormat;
  showCode?: boolean;
  topK?: number;
}

export function formatTerse(
  results: SearchResult[],
  options: Pick<FormatOptions, "topK">,
): string {
  const topK = options.topK ?? 10;
  const seen = new Set<string>();
  const lines: string[] = [];

  for (const { chunk, score, symbol } of results) {
    if (seen.has(chunk.id)) continue;
    seen.add(chunk.id);

    const symbolPart = chunk.symbol
      ? `${chunk.symbol} (${symbol?.type ?? "symbol"})`
      : "(no symbol)";
    const sig = extractSignature(chunk.content).split("\n")[0].trim();

    lines.push(
      `${chunk.file}:${chunk.start} | ${symbolPart} | ${score.toFixed(3)} | ${sig}`,
    );

    if (lines.length >= topK) break;
  }

  return lines.join("\n");
}

export interface JsonResult {
  rank: number;
  tier: "high" | "med" | "low";
  file: string;
  symbol: string | null;
  symbolType: string | null;
  lines: { start: number; end: number };
  score: number;
  code: string | null;
  signature: string | null;
  imports: Array<{ file: string; symbols: string[] }>;
  usedBy: string[];
  summary: string | null;
}

export interface JsonOutput {
  query: string;
  totalResults: number;
  results: JsonResult[];
}

export function formatJson(
  query: string,
  results: SearchResult[],
  depGraph: DependencyGraph,
  fileSummaries: FileSummaryIndex,
  options: FormatOptions,
): string {
  const importedByMap = computeImportedBy(depGraph);
  const showCode = options.showCode ?? false;
  const topK = options.topK ?? 10;

  const seen = new Set<string>();
  const jsonResults: JsonResult[] = [];

  for (const { chunk, score, symbol } of results) {
    if (seen.has(chunk.id)) continue;
    seen.add(chunk.id);

    const rank = jsonResults.length + 1;
    const tier = showCode ? "high" : getDisplayTier(rank);

    const fileDeps = depGraph[chunk.file];
    const usedBy = importedByMap.get(chunk.file) ?? [];

    let code: string | null = null;
    let signature: string | null = null;

    if (tier === "high") {
      const codeLines = chunk.content.split("\n");
      const limit = showCode ? codeLines.length : HIGH_CODE_LINES;
      code = codeLines.slice(0, limit).join("\n");
    } else if (tier === "med") {
      signature = extractSignature(chunk.content);
    }

    const fileSummary = fileSummaries[chunk.file];

    jsonResults.push({
      rank,
      tier,
      file: chunk.file,
      symbol: chunk.symbol ?? null,
      symbolType: symbol?.type ?? null,
      lines: { start: chunk.start, end: chunk.end },
      score: parseFloat(score.toFixed(4)),
      code,
      signature,
      imports: fileDeps?.imports ?? [],
      usedBy,
      summary: fileSummary?.summary ?? null,
    });

    if (jsonResults.length >= topK) break;
  }

  const output: JsonOutput = {
    query,
    totalResults: jsonResults.length,
    results: jsonResults,
  };

  return JSON.stringify(output, null, 2);
}

export function formatMarkdown(
  query: string,
  results: SearchResult[],
  depGraph: DependencyGraph,
  fileSummaries: FileSummaryIndex,
  callGraph: CallGraph,
  options: FormatOptions,
): string {
  const importedByMap = computeImportedBy(depGraph);
  const showCode = options.showCode ?? false;
  const topK = options.topK ?? 10;

  const lines: string[] = [];
  lines.push(`## Relevant code for: \`${query}\``);
  lines.push("");

  const seen = new Set<string>();
  let displayed = 0;

  for (const { chunk, score, symbol } of results) {
    if (seen.has(chunk.id)) continue;
    seen.add(chunk.id);

    const rank = displayed + 1;
    const tier = showCode ? "high" : getDisplayTier(rank);

    // Header
    lines.push(`### ${rank}. \`${chunk.file}\``);
    if (chunk.symbol) {
      const symType = symbol?.type ?? "symbol";
      lines.push(`**${symType}** \`${chunk.symbol}\`  `);
    }
    lines.push(
      `Lines ${chunk.start}–${chunk.end} · Score: ${score.toFixed(4)} · Tier: ${tier}`,
    );
    lines.push("");

    // Dependencies
    if (tier !== "low") {
      const fileDeps = depGraph[chunk.file];
      const usedBy = importedByMap.get(chunk.file) ?? [];

      if (fileDeps?.imports.length) {
        const maxDeps = tier === "high" ? 6 : 3;
        const shown = fileDeps.imports.slice(0, maxDeps);
        const hidden = fileDeps.imports.length - shown.length;

        lines.push("**Imports:**");
        for (const imp of shown) {
          const syms =
            imp.symbols.length > 0
              ? ` — \`${imp.symbols.slice(0, 4).join(", ")}\``
              : "";
          lines.push(`- \`${imp.file}\`${syms}`);
        }
        if (hidden > 0) lines.push(`- _…and ${hidden} more_`);
        lines.push("");
      }

      if (usedBy.length > 0) {
        const maxUsed = tier === "high" ? 4 : 2;
        const shown = usedBy.slice(0, maxUsed);
        const hidden = usedBy.length - shown.length;

        lines.push("**Used by (files):**");
        for (const caller of shown) {
          lines.push(`- \`${caller}\``);
        }
        if (hidden > 0) lines.push(`- _…and ${hidden} more_`);
        lines.push("");
      }

      // Call Graph context
      const symbolId = chunk.symbol ? `${chunk.file}:${chunk.symbol}` : null;
      const callInfo = symbolId ? callGraph[symbolId] : null;

      if (callInfo) {
        if (callInfo.calls.length > 0) {
          const maxCalls = tier === "high" ? 6 : 3;
          const shown = callInfo.calls.slice(0, maxCalls);

      // Call Graph context
      const symbolId = chunk.symbol ? `${chunk.file}:${chunk.symbol}` : null;
      const callInfo = symbolId ? callGraph[symbolId] : null;

      if (callInfo) {
        if (callInfo.calls.length > 0) {
          const maxCalls = tier === "high" ? 6 : 3;
          const shown = callInfo.calls.slice(0, maxCalls);
          const hidden = callInfo.calls.length - shown.length;

          lines.push("**Calls:**");
          for (const call of shown) {
            const loc = call.file ? ` (in \`${call.file}\`)` : "";
            lines.push(`- \`${call.name}\`${loc}`);
          }
          if (hidden > 0) lines.push(`- _…and ${hidden} more_`);
          lines.push("");
        }

        if (callInfo.calledBy.length > 0) {
          const maxCallers = tier === "high" ? 4 : 2;
          const shown = callInfo.calledBy.slice(0, maxCallers);
          const hidden = callInfo.calledBy.length - shown.length;

          lines.push("**Called by:**");
          for (const callerId of shown) {
            lines.push(`- \`${callerId}\``);
          }
          if (hidden > 0) lines.push(`- _…and ${hidden} more_`);
          lines.push("");
        }
      }
    }

    // Code / signature / summary
    if (tier === "high") {
      const codeLines = chunk.content.split("\n");
      const limit = showCode ? codeLines.length : HIGH_CODE_LINES;
      const preview = codeLines.slice(0, limit).join("\n");
      const ext = chunk.file.split(".").pop() ?? "";
      lines.push(`\`\`\`${ext}`);
      lines.push(preview);
      if (codeLines.length > limit) {
        lines.push(
          `// … (${codeLines.length - limit} more lines — use --show-code to expand)`,
        );
      }
      lines.push("```");
    } else if (tier === "med") {
      const sig = extractSignature(chunk.content);
      const ext = chunk.file.split(".").pop() ?? "";
      lines.push(`\`\`\`${ext}`);
      lines.push(sig);
      lines.push("```");
    } else {
      // LOW — summary if available
      const fileSummary = fileSummaries[chunk.file];
      if (fileSummary) {
        lines.push(`> ${fileSummary.summary}`);
      }
    }

    lines.push("");
    lines.push("---");
    lines.push("");

    displayed++;
    if (displayed >= topK) break;
  }

  if (displayed === 0) {
    lines.push("_No results found._");
  }

  return lines.join("\n");
}

import type {
  Chunk,
  EmbeddingCache,
  SearchResult,
  SymbolEntry,
  SymbolIndex,
} from "../core/types";
import { computeBM25Scores } from "./bm25";
import { vectorSearch } from "./vector";

export interface HybridOptions {
  alpha?: number; // Weight for vector search (0 to 1). Default: 0.7
  topK?: number;
}

export async function hybridSearch(
  query: string,
  queryEmbedding: number[] | null,
  chunks: Chunk[],
  cache: EmbeddingCache,
  symbols: SymbolIndex,
  options: HybridOptions = {},
): Promise<SearchResult[]> {
  const alpha = options.alpha ?? 0.7;
  const topK = options.topK ?? 10;

  // 1. Get Vector Scores
  let vectorResults: SearchResult[] = [];
  const oversample = topK * 3;
  if (queryEmbedding && queryEmbedding.length > 0) {
    vectorResults = vectorSearch(
      queryEmbedding,
      chunks,
      cache,
      symbols,
      oversample,
    );
  }

  // 2. Get BM25 Scores
  const bm25Results = computeBM25Scores(query, chunks, symbols, oversample);

  // 3. Normalize and Combine
  const combinedMap = new Map<
    string,
    { chunk: Chunk; score: number; symbol?: SymbolEntry }
  >();

  // Map for easy access and O(1) retrieval
  const vMap = new Map<string, { score: number; result: SearchResult }>();
  vectorResults.forEach((r) =>
    vMap.set(r.chunk.id, { score: r.score, result: r }),
  );

  const bMap = new Map<string, { score: number; result: SearchResult }>();
  // Normalize BM25 scores to [0, 1] relative to the max BM25 score found
  const maxBM25 =
    bm25Results.length > 0 ? Math.max(...bm25Results.map((r) => r.score)) : 1;
  bm25Results.forEach((r) =>
    bMap.set(r.chunk.id, { score: r.score / maxBM25, result: r }),
  );

  // Iterate over all chunks that appeared in either result
  const allIds = new Set([...vMap.keys(), ...bMap.keys()]);

  for (const id of allIds) {
    const vData = vMap.get(id);
    const bData = bMap.get(id);

    const vScore = vData?.score || 0;
    const bScore = bData?.score || 0;

    // Weighted combination
    const finalScore = alpha * vScore + (1 - alpha) * bScore;

    // Retrieve chunk and symbol in O(1)
    const result = vData?.result || bData?.result;
    if (result) {
      combinedMap.set(id, {
        chunk: result.chunk,
        score: finalScore,
        symbol: result.symbol,
      });
    }
  }

  // 4. Sort and Slice
  return Array.from(combinedMap.values())
    .sort((a, b) => b.score - a.score)
    .slice(0, topK);
}

export function mergeAdjacentChunks(
  results: SearchResult[],
  gapThreshold = 3,
): SearchResult[] {
  if (results.length <= 1) return results;

  // Group results by file
  const byFile = new Map<string, SearchResult[]>();
  for (const result of results) {
    const list = byFile.get(result.chunk.file) ?? [];
    list.push(result);
    byFile.set(result.chunk.file, list);
  }

  const merged: SearchResult[] = [];

  for (const fileResults of byFile.values()) {
    // Sort ascending by start line so we can merge left-to-right
    const sorted = [...fileResults].sort(
      (a, b) => a.chunk.start - b.chunk.start,
    );
    let cur = sorted[0];

    for (let i = 1; i < sorted.length; i++) {
      const next = sorted[i];

      if (next.chunk.start <= cur.chunk.end + gapThreshold) {
        // Deduplicate overlapping lines: compute how many lines of `next` are
        // already covered by `cur` based on line numbers, but cap at the actual
        // content length to handle reconstructed (previously merged) chunks.
        const overlapByLineNum = Math.max(
          0,
          cur.chunk.end - next.chunk.start + 1,
        );
        const nextLines = next.chunk.content.split("\n");
        const overlapLines = Math.min(overlapByLineNum, nextLines.length);
        const appendLines = nextLines.slice(overlapLines);

        const mergedContent =
          appendLines.length > 0
            ? cur.chunk.content + "\n" + appendLines.join("\n")
            : cur.chunk.content;

        const mergedSymbol =
          cur.chunk.symbol !== undefined &&
          cur.chunk.symbol === next.chunk.symbol
            ? cur.chunk.symbol
            : undefined;

        cur = {
          chunk: {
            id: cur.chunk.id + "+" + next.chunk.id,
            file: cur.chunk.file,
            start: cur.chunk.start,
            end: Math.max(cur.chunk.end, next.chunk.end),
            symbol: mergedSymbol,
            content: mergedContent,
          },
          score: Math.max(cur.score, next.score),
          symbol:
            mergedSymbol !== undefined
              ? (cur.symbol ?? next.symbol)
              : undefined,
        };
      } else {
        merged.push(cur);
        cur = next;
      }
    }

    merged.push(cur);
  }

  // Restore score-descending order
  return merged.sort((a, b) => b.score - a.score);
}

export function deduplicateBySimilarity(
  results: SearchResult[],
  cache: EmbeddingCache | null,
  threshold = 0.92,
): SearchResult[] {
  if (results.length <= 1) return results;

  // Precompute a mapping from chunk ID to embedding for O(1) retrieval during deduplication.
  let idToIndex: Map<string, number> | undefined;
  if (cache && cache.chunkIds) {
    idToIndex = new Map(cache.chunkIds.map((id, i) => [id, i]));
  }
  const embeddingOf = (id: string): number[] | null => {
    if (!cache) return null;
    // Dense binary format (chunkIds + vectors buffer)
    if (cache.chunkIds && cache.vectors && idToIndex) {
      const idx = idToIndex.get(id);
      if (idx !== undefined) {
        const dims = cache.dimensions;
        return Array.from(cache.vectors.subarray(idx * dims, idx * dims + dims));
      }
    }
    // Legacy map format
    return cache.embeddings?.[id] ?? null;
  };

  const selected: SearchResult[] = [];
  const selectedEmbeddings: Array<number[] | null> = [];

  for (const candidate of results) {
    const candidateEmb = embeddingOf(candidate.chunk.id);
    let tooSimilar = false;

    for (let i = 0; i < selected.length; i++) {
      const selEmb = selectedEmbeddings[i];
      if (candidateEmb && selEmb) {
        tooSimilar = cosineSimilarity(candidateEmb, selEmb) > threshold;
      } else {
        tooSimilar =
          jaccardSimilarity(candidate.chunk.content, selected[i].chunk.content) >
          0.65;
      }
      if (tooSimilar) break;
    }

    if (!tooSimilar) {
      selected.push(candidate);
      selectedEmbeddings.push(candidateEmb);
    }
  }

  return selected;
}

function jaccardSimilarity(a: string, b: string): number {
  const tokA = wordTokens(a);
  const tokB = wordTokens(b);
  if (tokA.size === 0 && tokB.size === 0) return 1;

  let intersection = 0;
  for (const t of tokA) if (tokB.has(t)) intersection++;
  const union = tokA.size + tokB.size - intersection;
  return union === 0 ? 0 : intersection / union;
}

function wordTokens(text: string): Set<string> {
  return new Set(
    text
      .toLowerCase()
      .split(/[\s\W]+/)
      .filter((t) => t.length >= 2),
  );
}

export function applyMMR(
  candidates: SearchResult[],
  cache: EmbeddingCache | null,
  topK: number,
  lambda = 0.5,
): SearchResult[] {
  if (candidates.length <= 1) return candidates.slice(0, topK);

  // Without vector data MMR cannot compute inter-result similarity.
  if (!cache?.vectors || !cache.chunkIds || !cache.dimensions) {
    return candidates.slice(0, topK);
  }

  const { vectors, chunkIds, dimensions } = cache;

  // Build a fast chunk-id → flat-buffer-index map.
  const idToIdx = new Map<string, number>();
  chunkIds.forEach((id, i) => idToIdx.set(id, i));

  // Normalise relevance scores to [0, 1] so lambda is meaningful regardless
  // of whether scores come from cosine similarity (already ~[0,1]) or BM25.
  // Use reduce instead of Math.max(...spread) to avoid call-stack overflow on large arrays.
  let maxScore = -Infinity;
  let minScore = Infinity;
  for (const r of candidates) {
    if (r.score > maxScore) maxScore = r.score;
    if (r.score < minScore) minScore = r.score;
  }
  const range = maxScore - minScore || 1;
  const relNorm = candidates.map((r) => (r.score - minScore) / range);

  // Pre-extract each candidate's vector as number[] so the inner loop avoids
  // repeated Array.from() allocations (O(n² * d) → O(n * d) allocations).
  const candidateVecs: Array<number[] | null> = candidates.map((r) => {
    const idx = idToIdx.get(r.chunk.id);
    if (idx === undefined) return null;
    const offset = idx * dimensions;
    return Array.from(vectors.subarray(offset, offset + dimensions));
  });

  const selected: SearchResult[] = [];
  // Flat-buffer indices of already-selected results (for similarity queries).
  const selectedVecIdx: number[] = [];

  // Track remaining candidates as index positions into `candidates`.
  const remaining = candidates.map((_, i) => i);

  while (selected.length < topK && remaining.length > 0) {
    let bestPos = -1; // position in `remaining`
    let bestMMR = -Infinity;

    for (let pos = 0; pos < remaining.length; pos++) {
      const candIdx = remaining[pos];
      const relevance = relNorm[candIdx];

      let maxSim = 0;
      if (selectedVecIdx.length > 0) {
        const vecA = candidateVecs[candIdx];
        if (vecA !== null) {
          for (const selIdx of selectedVecIdx) {
            const sim = cosineSimilarityBinary(
              vecA,
              vectors,
              selIdx * dimensions,
              dimensions,
            );
            if (sim > maxSim) maxSim = sim;
          }
        }
      }

      const mmrScore = lambda * relevance - (1 - lambda) * maxSim;
      if (mmrScore > bestMMR) {
        bestMMR = mmrScore;
        bestPos = pos;
      }
    }

    const chosenIdx = remaining[bestPos];
    selected.push(candidates[chosenIdx]);

      if (mmrScore > bestMMR) {
        bestMMR = mmrScore;
        bestPos = pos;
      }
    }

    const chosenIdx = remaining[bestPos];
    selected.push(candidates[chosenIdx]);

    const vecIdx = idToIdx.get(candidates[chosenIdx].chunk.id);
    if (vecIdx !== undefined) selectedVecIdx.push(vecIdx);

    remaining.splice(bestPos, 1);
  }

  return selected;
}

import type { SearchResult } from "../core/types";

// biome-ignore lint/suspicious/noExplicitAny: @xenova/transformers has no exported TS types
let model: any = null;
// biome-ignore lint/suspicious/noExplicitAny: @xenova/transformers has no exported TS types
let tokenizer: any = null;

/**
 * Initializes the reranker model and tokenizer if not already loaded.
 * Model: Xenova/ms-marco-MiniLM-L-6-v2
 *
 * Requires the optional peer dependency `@xenova/transformers`:
 *   npm install @xenova/transformers
 */

async function initReranker() {
  if (!model) {
    // biome-ignore lint/suspicious/noExplicitAny: dynamic optional dependency
    let transformers: any;
    try {
      transformers = require("@xenova/transformers");
    } catch {
      throw new Error(
        "The --rerank flag requires @xenova/transformers.\n" +
          "Install it with: npm install @xenova/transformers",
      );
    }
    const { AutoModelForSequenceClassification, AutoTokenizer } = transformers;
    model = await AutoModelForSequenceClassification.from_pretrained(
      "Xenova/ms-marco-MiniLM-L-6-v2",
      { quantized: false },
    );
    tokenizer = await AutoTokenizer.from_pretrained(
      "Xenova/ms-marco-MiniLM-L-6-v2",
    );
  }
}

export async function rerankResults(
  query: string,
  results: SearchResult[],
  topK: number = 10,
): Promise<SearchResult[]> {
  if (results.length === 0) return [];

  await initReranker();

  const reranked: SearchResult[] = [];

  // We only rerank the first 25 results to keep it fast
  const candidates = results.slice(0, 25);

  for (const res of candidates) {
    try {
      // Tokenize the pair
      const inputs = await tokenizer(query, {
        text_pair: res.chunk.content,
        truncation: true,
        padding: true,
      });

      // Get the raw logits
      const { logits } = await model(inputs);

      // For this model, the logit at index 0 is the relevance score
      const score = logits.data[0];

      reranked.push({
        ...res,
        score: score,
      });
    } catch (err) {
      console.warn(`Failed to rerank chunk ${res.chunk.id}:`, err);
      reranked.push(res);
    }
  }

  // Sort by the new cross-encoder logit (higher is more relevant)
  reranked.sort((a, b) => b.score - a.score);

  return reranked.slice(0, topK);
}

export function extractSignature(content: string): string {
  const lines = content.split("\n");
  const firstMeaningful = lines.find((l) => l.trim().length > 0) ?? "";

  // ── Interfaces and type aliases ──────────────────────────────────────────
  // These are inherently compact — the full declaration IS the signature.
  // Show up to 20 lines (rare for them to be longer).
  if (/^\s*(export\s+)?(type\s+\w|interface\s+\w)/.test(firstMeaningful)) {
    const slice = lines.slice(0, 20);
    if (lines.length > 20) slice.push("  …");
    return slice.join("\n").trim();
  }

  // ── File header / import blocks ──────────────────────────────────────────
  // Chunks that are just import statements — show first 5 lines.
  if (/^\s*import\s/.test(firstMeaningful)) {
    const slice = lines.slice(0, 5);
    if (lines.length > 5) slice.push(`  … (${lines.length - 5} more lines)`);
    return slice.join("\n").trim();
  }

  // ── Function / class / method declarations ───────────────────────────────
  const result: string[] = [];

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const trimmed = line.trimEnd();

    // Line ends with opening brace → body starts here.
    // Captures patterns like:
    //   ): Promise<void> {
    //   export class Foo extends Bar {
    //   } catch (e) {          (skip mid-function braces — result.length guard)
    if (/\{\s*(\/\/[^\n]*)?\s*$/.test(trimmed)) {
      // Strip the brace (and any trailing comment) and append { … }
      const withoutBrace = trimmed
        .replace(/\s*\{\s*(\/\/[^\n]*)?\s*$/, "")
        .trimEnd();
      result.push(
        (withoutBrace !== ""
          ? withoutBrace
          : trimmed.replace(/\{.*$/, "").trim()) + " { … }",
      );
      break;
    }

    // Arrow function with expression body:
    //   const f = (x: number) =>
    //     x * 2
    if (trimmed.endsWith("=>") && !trimmed.endsWith("=>>")) {
      result.push(trimmed + " …");
      break;
    }

    result.push(line);

    // Single-line declarations ending with `;` (e.g. `declare function f(): void;`)
    if (result.length === 1 && trimmed.endsWith(";")) break;

    // Safety cap
    if (result.length >= MAX_SIG_LINES) {
      result.push("  …");
      break;
    }
  }

  return result.join("\n").trim();
}

export function getDisplayTier(rank: number): DisplayTier {
  if (rank <= 3) return "high";
  if (rank <= 7) return "med";
  return "low";
}

import type {
  Chunk,
  EmbeddingCache,
  SearchResult,
  SymbolIndex,
} from "../core/types";

// ─── Cosine Similarity ────────────────────────────────────────────────────────

/**
 * Computes cosine similarity between two vectors.
 * Returns a value in [-1, 1]. For normalized embeddings (OpenAI, Ollama)
 * this is effectively in [0, 1] for semantically related pairs.
 */

export function cosineSimilarity(a: number[], b: number[]): number {
  if (a.length === 0 || a.length !== b.length) return 0;

  let dot = 0;
  let normA = 0;
  let normB = 0;

  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }

  const denom = Math.sqrt(normA) * Math.sqrt(normB);
  return denom === 0 ? 0 : dot / denom;
}

export function cosineSimilarityBinary(
  query: number[],
  vectors: Float32Array,
  offset: number,
  dims: number,
): number {
  let dot = 0;
  let normA = 0;
  let normB = 0;

  for (let i = 0; i < dims; i++) {
    const valB = vectors[offset + i];
    dot += query[i] * valB;
    normA += query[i] * query[i];
    normB += valB * valB;
  }

  const denom = Math.sqrt(normA) * Math.sqrt(normB);
  return denom === 0 ? 0 : dot / denom;
}

export function vectorSearch(
  queryEmbedding: number[],
  chunks: Chunk[],
  cache: EmbeddingCache,
  symbols: SymbolIndex,
  topK = 10,
): SearchResult[] {
  if (queryEmbedding.length === 0) return [];

  const scored: SearchResult[] = [];

  const { vectors, chunkIds, dimensions, hnswIndex } = cache;

  if (!vectors || !chunkIds) {
    return [];
  }
  if (hnswIndex) {
    try {
      const { HNSW } = require("hnsw");
      const index = HNSW.fromJSON(hnswIndex);
      // Increased efSearch for better accuracy
      const hnswResults = index.searchKNN(
        queryEmbedding,
        Math.max(topK * 2, 20),
        { efSearch: 64 },
      );

        const chunkById = new Map(chunks.map(c => [c.id, c]));
        const chunkResults: SearchResult[] = [];
        for (const res of hnswResults) {
          const chunkId = chunkIds[res.id];
          const chunk = chunkById.get(chunkId);
          if (chunk) {
            const symbol = chunk.symbol ? symbols[chunk.symbol] : undefined;
            chunkResults.push({ chunk, score: res.score, symbol });
          }
        }

      chunkResults.sort((a, b) => b.score - a.score);
      return chunkResults.slice(0, topK);
    } catch (e) {
      console.warn("HNSW search failed, falling back to exhaustive search:", e);
    }
  }

  // Fallback: Optimized path: binary search over contiguous buffer
  // Map chunkId to index for fast lookup
  const idToIndex = new Map<string, number>();
  chunkIds.forEach((id, i) => idToIndex.set(id, i));

  for (const chunk of chunks) {
    const idx = idToIndex.get(chunk.id);
    if (idx === undefined) continue;

    const score = cosineSimilarityBinary(
      queryEmbedding,
      vectors!,
      idx * dimensions,
      dimensions,
    );
    const symbol = chunk.symbol ? symbols[chunk.symbol] : undefined;
    scored.push({ chunk, score, symbol });
  }

  scored.sort((a, b) => b.score - a.score);
  return scored.slice(0, topK);
}

export function symbolLookup(
  query: string,
  chunks: Chunk[],
  symbols: SymbolIndex,
): SearchResult[] {
  const q = query.trim().toLowerCase();
  const words = q.split(/[\s\W]+/).filter((w) => w.length >= 2);

  const candidates: Array<{ name: string; score: number }> = [];

  for (const name of Object.keys(symbols)) {
    const lower = name.toLowerCase();
    if (lower === q) {
      candidates.push({ name, score: 1.0 });
    } else if (words.some((w) => lower === w)) {
      candidates.push({ name, score: 0.95 });
    } else if (words.some((w) => lower.startsWith(w) || w.startsWith(lower))) {
      candidates.push({ name, score: 0.8 });
    }
  }

  if (candidates.length === 0 || candidates.length > 5) return [];

  candidates.sort((a, b) => b.score - a.score);

  const results: SearchResult[] = [];
  for (const { name, score } of candidates) {
    const sym = symbols[name];
    const chunk = chunks.find((c) => c.symbol === name && c.file === sym.file);
    if (chunk) {
      results.push({ chunk, score, symbol: sym });
    }
  }

  return results;
}

export function keywordSearch(
  query: string,
  chunks: Chunk[],
  symbols: SymbolIndex,
  topK = 10,
): SearchResult[] {
  // Split query into meaningful terms (skip stop words shorter than 3 chars)
  const terms = query
    .toLowerCase()
    .split(/[\s\W]+/)
    .filter((t) => t.length >= 3);

  if (terms.length === 0) return [];

  const scored: SearchResult[] = chunks.map((chunk) => {
    const content = chunk.content.toLowerCase();
    let score = 0;

    for (const term of terms) {
      // Count occurrences
      let pos = 0;
      let count = 0;
      while ((pos = content.indexOf(term, pos)) !== -1) {
        count++;
        pos += term.length;
      }
      if (count > 0) {
        // TF normalized by content length (log-scaled to dampen large files)
        score += count / Math.log(content.length + 2);
      }
    }

    // Bonus: symbol name matches the query terms
    if (chunk.symbol) {
      const symLower = chunk.symbol.toLowerCase();
      if (terms.some((t) => symLower.includes(t))) {
        score *= 2;
      }
    }

    const symbol = chunk.symbol ? symbols[chunk.symbol] : undefined;
    return { chunk, score, symbol };
  });

  scored.sort((a, b) => b.score - a.score);
  return scored.filter((r) => r.score > 0).slice(0, topK);
}

import fs from "fs";
import os from "os";
import path from "path";
import type { EmbeddingCache } from "../core/types";

/** Maximum allowed size for embeddings.bin (512 MB) */
const MAX_CACHE_BYTES = 512 * 1024 * 1024;

/**
 * Manages the local per-developer embedding cache.
 *
 * Stored in ~/.vemora-cache/<projectId>/ — never in the repo.
 * Each developer builds their own cache after running `vemora index`.
 *
 * Design choice: dual-file storage per project.
 * Metadata and chunk IDs are stored in JSON (inspectable).
 * Vectors are stored as a contiguous Float32Array binary buffer (fast I/O).
 * The HNSW index is serialized to a separate JSON file for O(log N) search.
 */

export class EmbeddingCacheStorage {
  private cacheDir: string;
  private cachePath: string; // embeddings.json (metadata + chunkIds)
  private binPath: string; // embeddings.bin (raw floats)
  private hnswPath: string; // embeddings.hnsw.json (serialized HNSW)

  constructor(projectId: string) {
    this.cacheDir = path.join(os.homedir(), ".vemora-cache", projectId);
    this.cachePath = path.join(this.cacheDir, "embeddings.json");
    this.binPath = path.join(this.cacheDir, "embeddings.bin");
    this.hnswPath = path.join(this.cacheDir, "embeddings.hnsw.json");
  }

  load(): EmbeddingCache | null {
    if (!fs.existsSync(this.cachePath)) return null;

    try {
      const metadata = JSON.parse(fs.readFileSync(this.cachePath, "utf-8"));

      // Check if it's the legacy format (embeddings object instead of chunkIds list)
      if (metadata.embeddings && !metadata.chunkIds) {
        console.log("Migrating legacy JSON cache to binary format...");
        this.save(metadata as EmbeddingCache);
        return this.load(); // reload so vectors are read from the binary file
      }

      // New format: load metadata + binary vectors
      if (!fs.existsSync(this.binPath)) return metadata;

      const { size } = fs.statSync(this.binPath);
      if (size > MAX_CACHE_BYTES) {
        throw new Error(`Cache file too large (${size} bytes): ${this.binPath}`);
      }
      const binBuffer = fs.readFileSync(this.binPath);
      // Slice to a fresh ArrayBuffer to guarantee 4-byte alignment regardless
      // of Node.js buffer pool offsets (avoids RangeError on misaligned views).
      const ab = binBuffer.buffer.slice(
        binBuffer.byteOffset,
        binBuffer.byteOffset + binBuffer.byteLength,
      );
      const vectors = new Float32Array(ab);

      // Load HNSW index if it exists
      let hnswIndex = undefined;
      if (fs.existsSync(this.hnswPath)) {
        try {
          hnswIndex = JSON.parse(fs.readFileSync(this.hnswPath, "utf-8"));
        } catch (_e) {
          console.warn(
            "Failed to load HNSW index, it will be rebuilt on next index run.",
          );
        }
      }

      return {
        ...metadata,
        vectors,
        hnswIndex,
      };
    } catch (err) {
      console.error(`Failed to load cache from ${this.cachePath}:`, err);
      return null;
    }
  }

  save(cache: EmbeddingCache): void {
    fs.mkdirSync(this.cacheDir, { recursive: true });

    // If we have standard embeddings record, convert to binary
    if (cache.embeddings && Object.keys(cache.embeddings).length > 0) {
      const chunkIds = Object.keys(cache.embeddings);
      const dims = cache.dimensions;
      const vectors = new Float32Array(chunkIds.length * dims);

      chunkIds.forEach((id, i) => {
        const embedding = cache.embeddings![id];
        vectors.set(embedding, i * dims);
      });

      cache.chunkIds = chunkIds;

    const vectors = new Float32Array(chunkIds.length * dims);

    chunkIds.forEach((id, i) => {
      const embedding = cache.embeddings![id];
      vectors.set(embedding, i * dims);
    });

    cache.chunkIds = chunkIds;
    cache.vectors = vectors;
  }

  // Save metadata (exclude actual vectors/embeddings)
  const { vectors, embeddings, ...metadata } = cache;
  fs.writeFileSync(
    this.cachePath,
    JSON.stringify(metadata, null, 2),
    "utf-8",
  );

  // Save binary vectors
  if (vectors) {
    fs.writeFileSync(
      this.binPath,
      Buffer.from(vectors.buffer, vectors.byteOffset, vectors.byteLength),
    );
  }

  // Save HNSW index
  if (cache.hnswIndex) {
    fs.writeFileSync(this.hnswPath, JSON.stringify(cache.hnswIndex), "utf-8");
  }
}

update(
  newEmbeddings: Record<string, number[]>,
  cache: EmbeddingCache,
): EmbeddingCache {
  // Merge into legacy format first for simplicity, then save (which converts to bin)
  const currentEmbeddings = this.getEmbeddingsMap(cache);
  const updated: EmbeddingCache = {
    ...cache,
    embeddings: { ...currentEmbeddings, ...newEmbeddings },
    lastUpdated: new Date().toISOString(),
  };
  this.save(updated);
  return updated;
}

prune(validChunkIds: Set<string>, cache: EmbeddingCache): EmbeddingCache {
  const currentMap = this.getEmbeddingsMap(cache);
  const prunedMap: Record<string, number[]> = {};

  for (const id of validChunkIds) {
    if (currentMap[id]) {
      prunedMap[id] = currentMap[id];
    }
  }

  const updated: EmbeddingCache = {
    ...cache,
    embeddings: prunedMap,
    lastUpdated: new Date().toISOString(),
  };

  // Clear optimized fields to force re-generation from the pruned map
  delete updated.vectors;
  delete updated.chunkIds;

  this.save(updated);
  return updated;
}

/**
 * Helper to always get a Map, regardless of storage format
 */
private getEmbeddingsMap(cache: EmbeddingCache): Record<string, number[]> {
  if (cache.embeddings) return cache.embeddings;
